INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_034fa224aad88fe0fa',NULL,'pulse','/pʌls/','n. 脉冲, 脉搏, 情绪, 意向, 拍子, 豆类\nvi. 跳动, 脉跳\nvt. 使跳动, 用脉冲调制\n[计] 脉冲；英英释义：n. the rhythmic contraction and expansion of the arteries with each beat of the heart\nn. the rate at which the heart beats; usually measured to obtain a quick evaluation of a person''s health\nn. edible seeds of various pod-bearing plants (peas or beans or lentils etc.)\nv. produce or modulate (as electromagnetic waves) in the form of short bursts or pulses or cause an apparatus to produce pulses；词形变化：s:pulses/p:pulsed/i:pulsing/d:pulsed/3:pulses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
