INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_422952aa01fbe10551',NULL,'pure','/pjuә/','a. 纯的, 纯净的, 纯洁的, 清白的, 完美的, 无瑕的, 抽象的\n[医] 的, 纯净的；英英释义：a. free of extraneous elements of any kind\ns. free from discordant qualities\ns. concerned with theory and data rather than practice; opposed to applied\na. (used of persons or behaviors) having no faults; sinless；词形变化：t:purest/r:purer','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f3ecc3d502f9fabe4f',NULL,'purify','/''pjuәrifai/','vi. 变纯净\nvt. 使纯净, 净化, 提纯, 精炼；英英释义：v. remove impurities from, increase the concentration of, and separate through the process of distillation\nv. make pure or free from sin or guilt\nv. become clean or pure or free of guilt and sin；词形变化：p:purified/d:purified/i:purifying/3:purifies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8ede890404644c15ef',NULL,'purple','/''pә:pl/','n. 紫色, 帝位\na. 紫色的, 帝王的, 华而不实的\nv. (使)成紫色；英英释义：n. a purple color or pigment\nn. of imperial status\nv. become purple\nv. color purple；词形变化：s:purples/d:purpled/i:purpling/p:purpled/3:purples/r:purpler/t:purplest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d6a8daaae85364964d',NULL,'purpose','/''pә:pәs/','n. 目的, 意向, 决心, 用途, 效果, 论题\nvt. 意欲, 企图, 计划；英英释义：n. an anticipated outcome that is intended or that guides your planned actions\nv. reach a decision；词形变化：s:purposes/i:purposing/p:purposed/3:purposes/d:purposed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_570a6b3b4ddcd1f851',NULL,'purse','/pә:s/','n. 钱包, 小钱袋, 金钱, 募捐款, 囊状物\nv. 缩拢, 皱起；英英释义：n. a sum of money spoken of as the contents of a money purse\nn. a small bag for carrying money\nn. a sum of money offered as a prize\nv. contract one''s lips into a rounded shape；词形变化：p:pursed/s:purses/d:pursed/i:pursing/3:purses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b30e28de6c9479ffad',NULL,'pursue','/pә''sju:/','vt. 追赶, 追踪, 追随, 追求, 实行, 继续, 从事\nvi. 追赶, 继续；英英释义：v. follow in or as if in pursuit\nv. carry further or advance；词形变化：d:pursued/i:pursuing/p:pursued/3:pursues','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f359d24cab140d45be',NULL,'pursuit','/pә''sju:t/','n. 追踪, 追求, 追赶, 娱乐, 职业\n[法] 追捕, 追求；英英释义：n. the act of pursuing in an effort to overtake or capture\nn. a search for an alternative that meets cognitive criteria；词形变化：s:pursuits','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4042ce4c41785d4231',NULL,'puzzle','/''pʌzl/','n. 难题, 迷惑\nvt. 使困惑, 使为难\nvi. 迷惑, 苦思；英英释义：n. a particularly baffling problem that is said to have a correct solution\nn. a game that tests your ingenuity\nv. be uncertain about; think about without fully understanding or being able to decide；词形变化：s:puzzles/i:puzzling/p:puzzled/d:puzzled/3:puzzles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_482c8b4e314ac5a78b',NULL,'pyramid','/''pirәmid/','n. 角锥, 金字塔\nv. (使)成金字塔状, (使)渐增, (使)上涨；英英释义：n. a polyhedron having a polygonal base and triangular sides with a common vertex\nn. (stock market) a series of transactions in which the speculator increases his holdings by using the rising market value of those holdings as margin for further purchases\nn. a massive monument with a square base and four triangular sides; begun by Cheops around 2700 BC as royal tombs in ancient Egypt\nv. enlarge one''s holdings on an exchange on a continued rise by using paper profits as margin to buy additional amounts；词形变化：s:pyramids/i:pyramiding/p:pyramided/3:pyramids/d:pyramided','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4e8fb99c33559035e3',NULL,'qualification','/.kwɒlifi''keiʃәn/','n. 资格, 条件, 限制\n[计] 限定；英英释义：n. an attribute that must be met or complied with and that fits a person for something\nn. the act of modifying or changing the strength of some idea；词形变化：s:qualifications','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3cbada14feae8b5dd3',NULL,'qualify','/''kwɒlifai/','vi. 取得资格, 有资格\nvt. 使有资格, 使合格, 限定, 限制, 准予；英英释义：v. prove capable or fit; meet requirements\nv. pronounce fit or able\nv. make more specific\nv. make fit or prepared；词形变化：d:qualified/p:qualified/3:qualifies/i:qualifying','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4fa9bcd8dad47ce031',NULL,'qualitative','/''kwɒlitәtiv/','a. 性质的, 质的, 定性的；英英释义：a. involving distinctions based on qualities\na. relating to or involving comparisons based on qualities','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_857fdab1f3de90a544',NULL,'quality','/''kwɒlәti/','n. 品质, 特性, 才能, 质量\na. 优质的\n[计] 品质；英英释义：n. an essential and distinguishing attribute of something or someone\nn. a degree or grade of excellence or worth\nn. a characteristic property that defines the apparent individual nature of something\nn. high social status；词形变化：s:qualities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cdb4fa63effbdd5172',NULL,'quantify','/''kwɒntifai/','vt. 定量, 用数量表示, 测量；英英释义：v. use as a quantifier\nv. express as a number or measure or quantity；词形变化：d:quantified/i:quantifying/3:quantifies/p:quantified','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_64285e11ec4c2de3cb',NULL,'quantitative','/''kwɒntitәtiv/','a. 数量的, 定量的\n[医] 定量的, 数量的；英英释义：a. expressible as a quantity or relating to or susceptible of measurement\na. relating to the measurement of quantity\na. (of verse) having a metric system based on relative duration of syllables','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_eef98af3ade414a89a',NULL,'quantity','/''kwɒntәti/','n. 量, 数量, 总量\n[计] 数量; 量；英英释义：n. an adequate or large amount\nn. the concept that something has a magnitude and can be represented in mathematical expressions by a constant or a variable；词形变化：s:quantities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4233e7217256cc171d',NULL,'quarrel','/''kwɒrәl/','n. 吵架, 反目, 怨言, 方头凿\nvi. 吵架, 争论, 挑剔；英英释义：n. an angry dispute\nn. an arrow that is shot from a crossbow; has a head with four edges\nv. have a disagreement over something；词形变化：s:quarrels/p:quarrelled/i:quarrelling/d:quarrelled/3:quarrels','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0b7d93e13bc055e0f7',NULL,'quart','/kwɒ:t/','n. 夸脱\n[医] 夸脱(四分之一加仑)；英英释义：n. a United States liquid unit equal to 32 fluid ounces; four quarts equal one gallon\nn. a British imperial capacity measure (liquid or dry) equal to 2 pints or 1.136 liters\nn. a United States dry unit equal to 2 pints or 67.2 cubic inches；词形变化：s:quarts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d5d58d87edf6ab920f',NULL,'quarterly','/''kwɔ:tәli/','a. 季度的, 按季度的, 每季的\nadv. 按季, 每三个月, 每季一次\nn. 季刊；英英释义：n. a periodical that is published every quarter (or four issues per year)\na. of or relating to or consisting of a quarter\nr. in diagonally opposed quarters of an escutcheon\nr. in three month intervals；词形变化：s:quarterlies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ac051b2d95fcda75de',NULL,'quartz','/kwɒ:ts/','n. 石英\n[化] 石英；英英释义：n. a hard glossy mineral consisting of silicon dioxide in crystal form; present in most rocks (especially sandstone and granite); yellow sand is quartz with iron oxide impurities','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b7f22f5f018bfc3569',NULL,'queen','/''kwi:n/','n. 王后, 女王\nvt. 立为女王\nvi. 做女王；英英释义：n. the only fertile female in a colony of social insects such as bees and ants and termites; its function is to lay eggs\nn. a female sovereign ruler\nn. the wife or widow of a king\nn. something personified as a woman who is considered the best or most important of her kind；词形变化：s:queens/i:queening/p:queened/3:queens/d:queened','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_520d2336164e5315ce',NULL,'queer','/kwiә/','n. 怪人, 同性恋者\na. 奇怪的, 不舒服的, 可疑的\nvt. 搞糟；英英释义：v. put in a dangerous, disadvantageous, or difficult position；词形变化：s:queers/t:queerest/i:queering/r:queerer/3:queers/d:queered/p:queered','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9387508f599d6e6a3e',NULL,'quench','/kwentʃ/','vt. 熄灭, 结束, 使冷却, 将...淬火\nvi. 熄灭, 平息；英英释义：v. satisfy (thirst)\nv. electronics: suppress (sparking) when the current is cut off in an inductive circuit, or suppress (an oscillation or discharge) in a component or device\nv. reduce the degree of (luminescence or phosphorescence) in (excited molecules or a material) by adding a suitable substance；词形变化：i:quenching/d:quenched/p:quenched/3:quenches','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5dafab5f3069a6dfb2',NULL,'quest','/kwest/','n. 探索, 寻求, 调查\nv. 寻找, 找, 追寻猎物；英英释义：n. the act of searching for something\nv. make a search (for)\nv. search the trail of (game)\nv. seek alms, as for religious purposes；词形变化：s:quests/i:questing/p:quested/d:quested/3:quests','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7beb364b7e8dd24dec',NULL,'questionable','/''kwestʃәnәbl/','a. 可疑的\n[法] 可疑的, 有问题的, 不可靠的；英英释义：a. subject to question\ns. able to be refuted','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
