INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d303ecfd1058171e89',NULL,'queue','/kju:/','n. 辫子, 一队人, 队列\nvt. 使排队, 将...梳成辫子\nvi. 排队\n[计] 队列；英英释义：n. a line of people or vehicles waiting for something\nn. (information processing) an ordered list of tasks to be performed or messages to be transmitted\nn. a braid of hair at the back of the head；词形变化：s:queues/i:queuing/p:queued/d:queued/3:queues','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8b9fe0acfad12f4c70',NULL,'quilt','/kwilt/','n. 棉被\nvt. 加软衬料后缝制, 东拼西凑地编\nvi. 缝被子；英英释义：n. bedding made of two layers of cloth filled with stuffing and stitched together\nv. stitch or sew together\nv. create by stitching together；词形变化：s:quilts/i:quilting/d:quilted/p:quilted/3:quilts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ba2402816d7fa8c7c5',NULL,'quirk','/kwә:k/','n. 古怪举动, 俏皮话, 急转；英英释义：n. a narrow groove beside a beading\nv. twist or curve abruptly；词形变化：s:quirks/p:quirked/i:quirking','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4af776b5b3ef6c6afd',NULL,'quit','/kwit/','vi. 离开, 辞职, 停止\nvt. 离开, 放弃, 使解除, 停止\nn. 离开\n[计] 结束, 退出；英英释义：v put an end to a state or an activity\nv give up or retire from a position\nv go away or leave\nv turn away from; give up\nv give up in the face of defeat of lacking hope; admit defeat；词形变化：p:quit/0:quit/1:pd/i:quitting/d:quit/3:quits','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
