INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ff9e9eb2fde71c1ef0',NULL,'rack','/ræk/','n. 架, 行李架, 饲草架, 搁物架, 痛苦, 折磨, 齿条, 行云团\nvt. 把...放在架上, 在架上制作, 折磨, 使痛苦, 压榨, 榨取, 猛烈撕拉, 拷问\nvi. 变形, 倾斜, (云)随风飘, (马)小步跑\n[计] 机架；英英释义：n. framework for holding objects\nn. rib section of a forequarter of veal or pork or especially lamb or mutton\nn. an instrument of torture that stretches or disjoints or mutilates victims\nn. a support for displaying various articles；词形变化：s:racks/d:racked/p:racked/i:racking/3:racks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_47c793b99ff633240f',NULL,'racket','/''rækit/','n. 球拍, 喧闹, 杂乱无章\nvi. 喧闹\nvt. 用球拍打；英英释义：n. a loud and disturbing noise\nn. an illegal enterprise (such as extortion or fraud or drug peddling or prostitution) carried on for profit\nn. a sports implement (usually consisting of a handle and an oval frame with a tightly interlaced network of strings) used to strike a ball (or shuttlecock) in various games\nv. make loud and annoying noises；词形变化：s:rackets','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f7a99d7359a096ae1f',NULL,'radar','/''reidә/','n. 雷达, 无线电探测器\n[计] 雷达图；英英释义：n. measuring instrument in which the echo of a pulse of microwave radiation is used to detect and locate distant objects；词形变化：s:radars','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a27ffa99fbec73d26e',NULL,'radiant','/''reidiәnt/','a. 发光的, 明亮的, 辐射的, 容光焕发的\n[医] 放射的, 辐射的, 辐射物[质]；英英释义：s radiating or as if radiating light','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f51c0daab550c7fdbf',NULL,'radiate','/''reidieit/','vt. 放射, 散发, 辐射, 传播, 广播\nvi. 发光, 辐射, 流露\na. 有射线的, 辐射状的；英英释义：v. send out rays or waves\nv. send out real or metaphoric rays\nv. extend or spread outward from a center or focus or inward towards a center\nv. cause to be seen by emitting light as if in rays；词形变化：i:radiating/p:radiated/3:radiates/d:radiated','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_36d82db6119e1fde8f',NULL,'radiation','/.reidi''eiʃәn/','n. 辐射\n[化] 放射；英英释义：n. energy that is radiated or transmitted in the form of rays or waves or particles\nn. the act of spreading outward from a central source\nn. the spontaneous emission of a stream of particles or electromagnetic rays in nuclear decay\nn. the spread of a group of organisms into new habitats；词形变化：s:radiations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('6e08d0e4-59f7-448a-a098-c171e70cb5b5',NULL,'radical','/''rædikl/','n. 激进分子, 词根, 基础, 根式, 根\na. 激进的, 根本的, 基本的, 根的；英英释义：n. a person who has radical ideas or opinions\nn. (mathematics) a quantity expressed as the root of another quantity\nn. a character conveying the lexical meaning of a logogram\ns. arising from or going to the root or source；词形变化：s:radicals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
