INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_92a51896529214171e',NULL,'radioactive','/.reidiәu''æktiv/','a. 放射性的, 有放射能的\n[医] 放射性的, 放射的；英英释义：a. exhibiting or caused by radioactivity','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1bdd3ed07c4a44e073',NULL,'radius','/''reidiәs/','n. 半径, 范围, 辐射光线\n[电] 半径；英英释义：n. the length of a line segment between the center and circumference of a circle or sphere\nn. a straight line from the center to the perimeter of a circle (or from the center to the surface of a sphere)\nn. a circular region whose area is indicated by the length of its radius\nn. the outer and slightly shorter of the two bones of the human forearm；词形变化：s:radii','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
