INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9d1c065a46576ea58f',NULL,'rage','/reidʒ/','n. 愤怒, 情绪激动, 狂暴\nvi. 大怒, 狂吹, 流行；英英释义：n. a state of extreme anger\nn. something that is desired intensely\nn. violent state of the elements\nv. be violent; as of fires and storms；词形变化：p:raged/i:raging/d:raged/s:rages/3:rages','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5e334ad9e1f22340cb',NULL,'raid','/reid/','n. 袭击, 突袭, 搜捕\nv. 奇袭, 搜捕\n[计] 廉价磁盘冗余阵列；英英释义：n. an attempt by speculators to defraud investors\nv. search without warning, make a sudden surprise attack on\nv. take over (a company) by buying a controlling interest of its stock\nv. search for something needed or desired；词形变化：s:raids/p:raided/d:raided/i:raiding/3:raids','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0d51e72b1f7778a3f7',NULL,'rail','/reil/','n. 横杆, 围栏, 栏杆, 铁轨, 扶手, 秧鸡\nvt. 以横木围栏, 给...铺铁轨\nvi. 责骂, 抱怨；英英释义：n. short for railway\nn. a horizontal bar (usually of wood or metal)\nn. any of numerous widely distributed small wading birds of the family Rallidae having short wings and very long toes for running on soft mud\nv. complain bitterly；词形变化：s:rails/p:railed/d:railed/i:railing/3:rails','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_25228e8bb24990e10d',NULL,'railroad','/''reilrәud/','n. 铁路, 铁路公司\nvt. 铺设铁路, 用铁路运输\nvi. 在铁路工作；英英释义：v. supply with railroad lines\nv. transport by railroad；词形变化：s:railroads/d:railroaded/i:railroading/p:railroaded/3:railroads','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
