INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dedc8ad436eae0c183',NULL,'rake','/reik/','n. 耙子, 钱耙, 斜度, 浪子\nv. 搜索, 掠过, (用耙子)耙, (使)倾斜；英英释义：n. a dissolute man in fashionable society\nn. a long-handled tool with a row of teeth at its head; used to move leaves or loosen soil\nv. move through with or as if with a rake\nv. level or smooth with a rake；词形变化：p:raked/i:raking/d:raked/s:rakes/3:rakes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b53a6df2c77e3983fc',NULL,'rally','/''ræli/','n. 重振旗鼓, 集合, 群众集会, 跌停回升\nv. 重整旗鼓, 集合, 恢复精神, 团结, 挖苦, 嘲笑；英英释义：n. a large gathering of people intended to arouse enthusiasm\nn. the feat of mustering strength for a renewed effort\nn. a marked recovery of strength or spirits during an illness\nn. an automobile race run over public roads；词形变化：s:rallies/p:rallied/i:rallying/d:rallied/3:rallies','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
