INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_333fbc4959714416fb',NULL,'real','/''riәl/','a. 真的, 真实的, 实际的, 实在的, 不动(产)的, 实数的\nn. 实数, 现实\nadv. 真正地；英英释义：n. the basic unit of money in Brazil; equal to 100 centavos\nn. an old small silver Spanish coin\na. being or occurring in fact or actuality; having verified existence; not illusory; not ghosts"\na. no less than what is stated; worthy of the name','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
