INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_68799cb8ae05670fc2',NULL,'recognize','/''rekәgnaiz/','vt. 认出, 认可, 承认, 公认, 识别, 赏识\nvi. 承认, 具结；英英释义：v. be fully aware or cognizant of\nv. perceive to be the same\nv. exhibit recognition for (an antigen or a substrate)\nv. show approval or appreciation of；词形变化：d:recognized/p:recognized/i:recognizing/3:recognizes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
