INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3445a236dc7686fb19',NULL,'recurrent','/ri''kʌrәnt/','a. 再发生的, 定期重复的, 循环的\n[医] 复发的, 再发的, 回归的；英英释义：s recurring again and again','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b3f3a125085e4120ef',NULL,'recycle','/.ri:''saikl/','vt. 使再循环, 重新利用, 再制\nn. 再循环；英英释义：v. cause to repeat a cycle\nv. use again after processing；词形变化：i:recycling/d:recycled/3:recycles/p:recycled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_99f9f23e2104590bf2',NULL,'reduce','/ri''dju:s/','vt. 减少, 分解, 降低, 使衰退, 把...分解, 把...归纳\nvi. 减少, 减肥, 缩小\n[计] 缩小；英英释义：v. cut down on; make a reduction in\nv. make less complex\nv. bring to humbler or weaker state or condition\nv. simplify the form of a mathematical equation of expression by substituting one term for another；词形变化：d:reduced/i:reducing/3:reduces/p:reduced','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bf31b1df27f9808947',NULL,'reduction','/ri''dʌkʃәn/','n. 减少, 缩影, 变化\n[化] 还原；英英释义：n. any process in which electrons are added to an atom or ion (as by removing oxygen or adding hydrogen); always occurs accompanied by oxidation of the reducing agent\nn. the act of reducing complexity；词形变化：s:reductions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_017741157a6a48eebb',NULL,'redundancy','/ri''dʌndәnsi/','n. 过多, 冗长, 累赘, 多余, 冗余位, 冗余度, 冗余码, 多余信息\n[计] 冗余；英英释义：n. repetition of messages to reduce the probability of errors in transmission\nn. the attribute of being superfluous and unneeded\nn. (electronics) a system design that duplicates components to provide alternatives in case one component fails\nn. repetition of an act needlessly；词形变化：s:redundancies','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('0db028f5-b0de-48b8-9ef7-215858af6646',NULL,'redundant','/ri''dʌndәnt/','a. 多余的, 过多的, 冗长的\n[医] 过多的, 多余的；英英释义：s more than is needed, desired, or required\ns repetition of same sense in different words','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_faff6ada240d4baf12',NULL,'reed','/ri:d/','n. 芦苇, 芦笛, 簧舌, 纤弱的人\nvt. 用芦苇盖, 用小凸嵌线装饰；英英释义：n. tall woody perennial grasses with hollow slender stems especially of the genera Arundo and Phragmites\nn. United States journalist who reported on the October Revolution from Petrograd in 1917; founded the Communist Labor Party in America in 1919; is buried in the Kremlin in Moscow (1887-1920)\nn. United States physician who proved that yellow fever is transmitted by mosquitoes (1851-1902)\nn. a vibrator consisting of a thin strip of stiff material that vibrates to produce a tone when air streams over it；词形变化：s:reeds/i:reeding','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_80f94023d76508471f',NULL,'reel','/ri:l/','n. 卷轴, 一卷, 纺车, 旋转, 蹒跚\nvt. 卷...于轴上, 绕, 使旋转\nvi. 蹒跚地走, 旋转, 眩晕, 摇晃, 退缩\n[计] 卷; 盘；英英释义：n. a roll of photographic film holding a series of frames to be projected by a movie projector\nn. music composed for dancing a reel\nn. winder consisting of a revolving spool with a handle; attached to a fishing rod\nn. a lively dance of Scottish Highlanders; marked by circular moves and gliding steps；词形变化：i:reeling/p:reeled/s:reels/3:reels/d:reeled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e36dd6ed0352f1450b',NULL,'refer','/ri''fә:/','vt. 提交, 归诸于, 把...提交, 使求助于\nvi. 提到, 涉及, 查阅, 查询, 咨询；英英释义：v. be relevant to\nv. think of, regard, or classify under a subsuming principle or with a general group or in relation to another\nv. send or direct for treatment, information, or a decision\nv. use a name to designate；词形变化：d:referred/3:refers/i:referring/p:referred','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c4d0f3e8a2917bd0d7',NULL,'referee','/.refә''ri:/','n. 仲裁人, 调解人, 裁判员\nv. 仲裁, 裁判；英英释义：n. (sports) the chief official (as in boxing or American football) who is expected to ensure fair play\nn. an attorney appointed by a court to investigate and report on a case\nv. be a referee or umpire in a sports competition\nv. evaluate professionally a colleague''s work；词形变化：s:referees/d:refereed/i:refereeing/p:refereed/3:referees','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ffc4c3f7046e9b9572',NULL,'reference','/''refәrәns/','n. 参考, 索引, 参照\nvt. 给...加上参考资料\nvt. 引用\nvi. 引用\n[计] 引用；英英释义：n. the most direct or specific meaning of a word or expression; the class of objects that an expression refers to\nn. the act of referring or consulting\nn. a publication (or a passage from a publication) that is referred to\nn. the relation between a word or phrase and the object or idea it refers to；词形变化：s:references/p:referenced/d:referenced/i:referencing/3:references','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_62e7566c982b552f0f',NULL,'refine','/ri''fain/','vt. 精炼, 净化, 使优雅, 使精炼\nvi. 被精炼, 被净化；英英释义：v. treat or prepare so as to put in a usable condition\nv. reduce to a fine, unmixed, or pure state; separate from extraneous matter or cleanse from impurities\nv. attenuate or reduce in vigor, strength, or validity by polishing or purifying\nv. make more precise or increase the discriminatory powers of；词形变化：i:refining/d:refined/p:refined/3:refines','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_08b4f9026d4a031df7',NULL,'reflect','/ri''flekt/','vt. 反射, 反映, 招致, 深思\nvi. 被反射, 映出, 深思, 考虑, 指责；英英释义：v. manifest or bring back\nv. to throw or bend back (from a surface)\nv. be bright by reflecting or casting light\nv. show an image of；词形变化：3:reflects/d:reflected/i:reflecting/p:reflected','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_641b1d406a82e476de',NULL,'reflection','/ri''flekʃәn/','n. 反映, 沉思, 映像, 想法, 责难\n[计] 反射；英英释义：n. the phenomenon of a propagating wave (light or sound) being thrown back from a surface\nn. the image of something as reflected by a mirror (or other reflective material)\nn. (mathematics) a transformation in which the direction of one axis is reversed\nn. the ability to reflect beams or rays；词形变化：s:reflections','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d3effc006311313f67',NULL,'reform','/ri''fɒ:m/','n. 改革, 改正, 改造\nvt. 改革, 改过, 革新, 重整\nvi. 革新, 改过；英英释义：n. a change for the better as a result of correcting abuses\nn. a campaign aimed to correct abuses or malpractices\nn. self-improvement in behavior or morals by abandoning some vice\nv. make changes for improvement in order to remove abuse and injustices；词形变化：s:reforms/d:reformed/i:reforming/p:reformed/3:reforms','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_76f582cce06423638b',NULL,'refrain','/ri''frein/','n. 重复的话, 叠句, 副歌\nvi. 节制, 避免, 克制；英英释义：n. the part of a song where a soloist is joined by a group of singers\nv. resist doing something；词形变化：p:refrained/i:refraining/d:refrained/3:refrains/s:refrains','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e855520102fda96b3b',NULL,'refresh','/ri''freʃ/','vt. 使清新, 使恢复, 使生气蓬勃\nvi. 提起精神, 恢复精神, 吃点心, 喝饮料\nvt. 刷新, 重新整理\nvi. 刷新, 重新整理\n[计] 刷新, 重新整理；英英释义：v. make (to feel) fresh\nv. make fresh again；词形变化：p:refreshed/d:refreshed/i:refreshing/3:refreshes/s:refreshes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c7d1019f164e14e795',NULL,'refreshment','/ri''freʃmәnt/','n. 点心, 起提神作用的事物, 精神爽快；英英释义：n. snacks and drinks served as a light meal\nn. activity that refreshes and recreates; activity that renews your health and spirits by enjoyment and relaxation；词形变化：s:refreshments','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3f07acf7c3872515c3',NULL,'refuge','/''refju:dʒ/','n. 避难所, 安全地带, 避难, 庇护\nvi. 躲避\nvt. 给予...庇护；英英释义：n. a shelter from danger or hardship；词形变化：s:refuges','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
