INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_df3d815afab2ac5cce',NULL,'refund','/''ri:fʌnd/','n. 偿还\nvt. 付还, 偿还借款\nvi. 归还, 偿还；英英释义：n. money returned to a payer\nn. the act of returning money received previously\nv. pay back；词形变化：s:refunds/d:refunded/p:refunded/i:refunding/3:refunds','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e371dc8d9097b154d0',NULL,'refusal','/ri''fju:zl/','n. 拒绝, 推却, 优先决定权\n[法] 拒绝, 谢绝, 取舍权；英英释义：n. the act of refusing\nn. a message refusing to accept something that is offered；词形变化：s:refusals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_771952c375c4ab793e',NULL,'refuse','/ri''fju:z/','vt. 拒绝, 谢绝\nvi. 拒绝\nn. 废物\na. 扔掉的, 无用的；英英释义：v. show unwillingness towards\nv. refuse to accept；词形变化：p:refused/d:refused/i:refusing/3:refuses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
