INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0c8e9306e18338b51d',NULL,'regard','/ri''gɑ:d/','n. 关心, 注意, 尊敬, 关系, 问候\nvt. 视为, 注意, 考虑, 和...有关, 看待\nvi. 注视, 注意；英英释义：n. (usually plural) a polite expression of desire for someone''s welfare\nn. a feeling of friendship and esteem\nv. look at attentively；词形变化：d:regarded/3:regards/p:regarded/i:regarding','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3411bb52e68903b635',NULL,'regarding','/ri''gɑ:diŋ/','prep. 关于；英英释义：v deem to be\nv look at attentively\nv connect closely and often incriminatingly；词形变化：0:regard/1:i','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
