INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ac8ce916080aa58731',NULL,'regenerate','/ri''dʒenәreit/','vt. 使再生, 重建, 革新\nvi. 新生, 再生\na. 新生的, 再生的\n[计] 再生; 重写；英英释义：v. reestablish on a new, usually improved, basis or make new or like new\nv. amplify (an electron current) by causing part of the power in the output circuit to act upon the input circuit\nv. return to life; get or give new life or energy\nv. replace (tissue or a body part) through the formation of new tissue；词形变化：i:regenerating/d:regenerated/3:regenerates/p:regenerated/s:regenerates','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3d30a596371fed8fd5',NULL,'regime','/rei''ʒi:m/','n. 政权, 当权期间, 政体, 社会制度, 体制, 情态\n[医] 制度, 生活制度；英英释义：n the organization that is the governing authority of a political unit\nn (medicine) a systematic plan for therapy (often including diet)；词形变化：s:regimes','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c50cfd5e8fa40c4f21',NULL,'region','/''ri:dʒәn/','n. 区域, 地带, 地区, 领域, 范围, 区\n[计] 区, 区域；英英释义：n. the extended spatial location of something\nn. a large indefinite location on the surface of the Earth\nn. the approximate amount of something (usually used prepositionally as in `in the region of'')\nn. a knowledge domain that you are interested in or are communicating about；词形变化：s:regions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_91b29a5e16a42d51a2',NULL,'register','/''redʒistә/','n. 寄存器, 记录, 登记簿, 注册\nvt. 记录, 注册, 提示, 表达, 把...挂号\nvi. 登记, 注册, 挂号\n[计] 寄存器；英英释义：n. an official written record of names or events or transactions\nn. (music) the timbre that is characteristic of a certain range and manner of production of the human voice or of different pipe organ stops or of different musical instruments\nn. a book in which names and transactions are listed\nn. (computer science) memory device that is the part of computer memory that has a specific address and that is used to hold information of a specific kind；词形变化：d:registered/s:registers/p:registered/i:registering/3:registers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_51980b8132207fe30e',NULL,'regret','/ri''gret/','n. 遗憾, 后悔, 悔恨, 抱歉, 歉意\nvt. 为...感到遗憾, 后悔, 惋惜, 懊悔, 抱歉\nvi. 感到抱歉；英英释义：v. feel sad about the loss or absence of\nv. decline formally or politely\nv. express with regret；词形变化：p:regretted/s:regrets/i:regretting/d:regretted/3:regrets','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4efe447405ad9a2f86',NULL,'regular','/''regjulә/','a. 规则的, 常例的, 有秩序的, 整齐的, 等边的, 定期的, 经常的, 合格的, 常备军的\nn. 正规军, 正式队员\nadv. 经常地\nn. 正常体\n[计] 正常体；英英释义：n. a regular patron\nn. a soldier in the regular army\nn. a dependable follower (especially in party politics)\nn. a garment size for persons of average height and weight；词形变化：s:regulars','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d98b7cb7eff3b80f3d',NULL,'regulate','/''regjuleit/','vt. 管理, 控制, 调节, 调整, 校准\n[经] 控制, 管理；英英释义：v. fix or adjust the time, amount, degree, or rate of\nv. bring into conformity with rules or principles or usage; impose regulations；词形变化：d:regulated/i:regulating/3:regulates/p:regulated','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6c040d53c07e12d10c',NULL,'regulation','/.regju''leiʃәn/','n. 规则, 管理, 调整\n[计] 调整; 规章; 规则; 调节；英英释义：n. an authoritative rule\nn. the state of being controlled or governed\nn. (embryology) the ability of an early embryo to continue normal development after its structure has been somehow damaged or altered\nn. the act of bringing to uniformity; making regular；词形变化：s:regulations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6dcf06cd3feb32f7b0',NULL,'rehearsal','/ri''hә:sl/','n. 预演, 排演, 练习, 叙述, 复述\n[法] 详述, 列举事实, 复述；英英释义：n. a practice session in preparation for a public performance (as of a play or speech or concert)\nn. (psychology) a form of practice; repetition of information (silently or aloud) in order to keep it in short-term memory；词形变化：s:rehearsals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b9ff954ed4954b702b',NULL,'reign','/rein/','v. 为王，为君；当政；统治\nn. 为王，为君；当政；统治；英英释义：n. a period during which something or somebody is dominant or powerful\nn. the period during which a monarch is sovereign\nn. royal authority; the dominion of a monarch\nv. have sovereign power；词形变化：p:reigned/3:reigns/s:reigns/i:reigning/d:reigned','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7403751583746a060d',NULL,'rein','/rein/','n. 缰绳, 统治, 支配\nvt. 驾驭, 以缰绳控制, 控制\nvi. 勒住马；英英释义：n. one of a pair of long straps (usually connected to the bit or the headpiece) used to control a horse\nn. any means of control\nv. stop or slow up one''s horse or oneself by or as if by pulling the reins\nv. stop or check by or as if by a pull at the reins；词形变化：s:reins/p:reined/d:reined/i:reining/3:reins','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('7549924b-590f-4042-ba26-b8c63968f46f',NULL,'reinforce','/.ri:in''fɒ:s/','vt. 加强, 增援, 补充\nvi. 求援, 得到增援\nn. 加固材料；英英释义：v. make stronger\nv. strengthen and support with rewards；词形变化：d:reinforced/3:reinforces/i:reinforcing/p:reinforced','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_574e5f447f17ef77f9',NULL,'reject','/ri''dʒekt/','n. 被拒之人, 被弃之物, 不合格品, 次品\nvt. 拒绝, 抵制, 否决, 驳回, 丢弃, 呕出；英英释义：v. refuse to accept or acknowledge\nv. reject with contempt\nv. refuse entrance or membership；词形变化：d:rejected/p:rejected/i:rejecting/3:rejects/s:rejects','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_80cb377b7d11d6fdd3',NULL,'rejoice','/ri''dʒɒis/','vt. 使欢喜\nvi. 欣喜, 高兴, 庆祝；英英释义：v. feel happiness or joy；词形变化：i:rejoicing/p:rejoiced/3:rejoices/d:rejoiced','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5970ecbc658be2f28f',NULL,'relate','/ri''leit/','vt. 讲, 叙述, 使互相关联\nvi. 有关, 符合, 相处得好；英英释义：v. give an account of\nv. be in a relationship with\nv. have or establish a relationship to；词形变化：i:relating/d:related/3:relates/p:related','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6170f4c83ceb8e09df',NULL,'relation','/ri''leiʃәn/','n. 关系, 联系, 叙述, 故事, 家属, 亲戚\n[计] 关系；英英释义：n. an abstraction belonging to or characteristic of two entities or parts together\nn. an act of narration\nn. (usually plural) mutual dealings or connections among persons or groups；词形变化：s:relations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f36a759ec6ec597694',NULL,'relationship','/ri''leiʃәnʃip/','n. 关系, 关联\n[医] 关系；英英释义：n. a relation between people; (`relationship'' is often used where `relation'' would serve, as in `the relationship between inflation and unemployment'', but the preferred usage of `relationship'' is for human relations or states of relatedness)\nn. a state of connectedness between people (especially an emotional connection)\nn. a state involving mutual dealings between people or parties or countries；词形变化：s:relationships','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4f6c85e035cf2cc0d0',NULL,'relative','/''relәtiv/','n. 亲戚, 关系词\na. 有关系的, 相对的, 比较的；英英释义：n. a person related by blood or marriage\nn. an animal or plant that bears a relationship to another (as related by common descent or by membership in the same genus)\na. estimated by comparison; not absolute or complete；词形变化：s:relatives','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e1fd4ee816343b8764',NULL,'relativity','/.relә''tiviti/','n. 有关系, 相关性, 相对性\n[化] 相对性；英英释义：n. (physics) the theory that space and time are relative concepts rather than absolute concepts\nn. the quality of being relative and having significance only in relation to something else；词形变化：s:relativities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0498a1cd78092424e1',NULL,'relax','/ri''læks/','vi. 放松, 松懈, 松弛, 变从容, 休息, 休养\nvt. 使松弛, 缓和, 使松懈, 使休息；英英释义：v. become less tense, rest, or take one''s ease\nv. make less taut\nv. cause to feel relaxed\nv. become less tense, less formal, or less restrained, and assume a friendlier manner；词形变化：p:relaxed/i:relaxing/d:relaxed/3:relaxes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_91860f8560e9b7aded',NULL,'relay','/''ri:lei/','n. 驿马, 替班, 中继, 接力\nvt. 分程传递, 转播, 使接替\nvi. 接力传送, 转播；英英释义：n. the act of passing something along from one person or group to another\nn. a crew of workers who relieve another crew\nn. a fresh team to relieve weary draft animals\nn. a race between teams; each member runs or swims part of the distance；词形变化：d:relayed/i:relaying/p:relayed/s:relays/3:relays','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1365e9b30ad230dd1d',NULL,'release','/ri''li:s/','n. 释放, 发泄, 豁免, 发行, 释放证书\nvt. 释放, 解除, 放松, 豁免, 免除, 发布, 放弃, 让与\nn. 发布\n[计] 版本, 发布；英英释义：n. merchandise issued for sale or public showing (especially a record or film)\nn. a process that liberates or discharges something\nn. a device that when pressed will release part of a mechanism\nn. activity that frees or expresses creative energy or emotion；词形变化：d:released/i:releasing/p:released/s:releases/3:releases','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
