INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5913dcee5f96558e35',NULL,'retrospection','/.retrә''spekʃәn/','n. 回顾, 追忆, 反省\n[医] 追想, 回忆；英英释义：n. reference to things past\nn. memory for experiences that are past；词形变化：s:retrospections','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
