INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_684c369dade667ed6e',NULL,'reveal','/ri''vi:l/','vt. 露出, 显示, 透露, 揭露, 泄露, (神)启示\nn. 窗侧, 门侧；英英释义：v. disclose directly or through prophets；词形变化：d:revealed/p:revealed/3:reveals/i:revealing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d45b7def351559a1c3',NULL,'revelation','/.revi''leiʃәn/','n. 揭露, 泄露, 发觉, 默示, 启示；英英释义：n. an enlightening or astonishing disclosure\nn. communication of knowledge to man by a divine or supernatural agency\nn. the last book of the New Testament; contains visionary descriptions of heaven and of conflicts between good and evil and of the end of the world; attributed to Saint John the Apostle；词形变化：s:revelations','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4717591f52649fb582',NULL,'revenge','/ri''vendʒ/','n. 报仇, 复仇, 报复\nvt. 报仇, 报复；英英释义：v. take revenge for a perceived wrong；词形变化：d:revenged/s:revenges/i:revenging/p:revenged/3:revenges','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6fa2eb3c990cd4acb6',NULL,'revenue','/''revinju:/','n. 收入, 岁入, 税收, 税务局\n[经] 岁入, 税收, 税务局；英英释义：n the entire amount of income before any deductions are made\nn government income due to taxation；词形变化：s:revenues','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9ffb1d325d26918de0',NULL,'reverse','/ri''vә:s/','n. 相反, 背面, 倒退, 挫折, 失败\na. 反面的, 相反的, 反向的, 颠倒的\nvt. 使颠倒, 使逆转, 使倒退, 使反向\nvi. 倒退, 反向, 倒转, 反转\n[计] 反转；英英释义：n. a relation of direct opposition\nn. the gears by which the motion of a machine can be reversed\nn. an unfortunate happening that hinders or impedes; something that is thwarting or frustrating\nn. the side of a coin or medal that does not bear the principal design；词形变化：d:reversed/i:reversing/p:reversed/3:reverses/s:reverses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2d57962a6ee8f8e905',NULL,'review','/ri''vju:/','n. 检讨, 复习, 回顾, 检阅, 评论\nvt. 温习, 检讨, 评论, 再检察, 复审\nvi. 复习功课, 写评论；英英释义：n. an essay or article that gives a critical evaluation (as of a book or play)\nn. (accounting) a service (less exhaustive than an audit) that provides some assurance to interested parties as to the reliability of financial data\nn. a periodical that publishes critical essays on current affairs or literature or art\nn. (law) a judicial reexamination of the proceedings of a court (especially by an appellate court)；词形变化：d:reviewed/s:reviews/i:reviewing/p:reviewed/3:reviews','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_674afebf347e6d70b9',NULL,'revise','/ri''vaiz/','n. 校订, 修正, 改样\nvt. 校订, 修正, 校正；英英释义：v. make revisions in；词形变化：d:revised/i:revising/p:revised/3:revises','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_646b5d24c410fa420b',NULL,'revive','/ri''vaiv/','vt. 使苏醒, 使复兴, 使振奋, 回想起, 重播\nvi. 苏醒, 复活, 复兴, 恢复精神；英英释义：v. be brought back to life, consciousness, or strength\nv. restore from a depressed, inactive, or unused state；词形变化：d:revived/i:reviving/p:revived/3:revives','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_969e7dcd370f183cbd',NULL,'revolt','/ri''vәult/','n. 叛乱, 反抗, 反感\nvi. 叛乱, 反抗, 起义, 厌恶, 反感\nvt. 使反感, 使恶心；英英释义：v. make revolution；词形变化：s:revolts/p:revolted/d:revolted/i:revolting/3:revolts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f87d6fffdaf00665ee',NULL,'revolution','/.revә''lu:ʃәn/','n. 革命, 大变革, 旋转, 转数, 循环\n[化] 回转；英英释义：n. a drastic and far-reaching change in ways of thinking and behaving\nn. the overthrow of a government by those who are governed；词形变化：s:revolutions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1daedd727529071ede',NULL,'revolutionary','/.revә''lu:ʃәnәri/','n. 革命者, 革命党人\na. 革命的, 革命性的；英英释义：s. markedly new or introducing radical change\na. relating to or having the nature of a revolution\na. advocating or engaged in revolution；词形变化：s:revolutionaries','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
