INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9fdad40650664a8a0a',NULL,'reward','/ri''wɒ:d/','n. 报酬, 酬谢, 赏金\nvt. 奖赏, 酬谢, 给...应有报应；英英释义：n. payment made in return for a service rendered\nn. an act performed to strengthen approved behavior\nn. the offer of money for helping to find a criminal or for returning lost property\nv. act or give recompense in recognition of someone''s behavior or actions；词形变化：s:rewards/d:rewarded/i:rewarding/p:rewarded/3:rewards','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_da3e6bb3cce07c1974',NULL,'rhythm','/''riðәm/','n. 旋律, 节奏, 韵律, 匀称, 张弛节律\n[医] 节律；英英释义：n. the basic rhythmic unit in a piece of music\nn. recurring at regular intervals\nn. the arrangement of spoken words alternating stressed and unstressed elements；词形变化：s:rhythms','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_98ed9cbe71c32d6b41',NULL,'rib','/rib/','n. 肋骨, 肋状物, 笑话\nvt. 装肋状物于, 戏弄；英英释义：n. support resembling the rib of an animal\nn. any of the 12 pairs of curved arches of bone extending from the spine to or toward the sternum in humans (and similar bones in most vertebrates)\nn. cut of meat including one or more ribs\nn. a teasing remark；词形变化：s:ribs/i:ribbing/p:ribbed/3:ribs/d:ribbed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_38ce6027dc7b549600',NULL,'ribbon','/''ribәn/','n. 缎带, 色带, 带状物\nvt. 用丝带装饰, 把...撕成条状\nvi. 形成带状\n[计] 带状条, 格式栏；英英释义：n. any long object resembling a thin line\nn. a long strip of inked material for making characters on paper with a typewriter\nn. notion consisting of a narrow strip of fine material used for trimming；词形变化：s:ribbons/i:ribboning','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4de4cd71032fd522a0',NULL,'rid','/rid/','vt. 免除, 以...清除, 使获自由, 使摆脱\n[法] 免除, 清除, 摆脱；英英释义：v. relieve from；词形变化：d:rid/0:rid/1:dp/i:ridding/p:rid/3:rids','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_52fa579877a9c7ad11',NULL,'riddle','/''ridl/','n. 谜, 谜语, 粗筛\nvt. 解谜, 给...出谜, 筛, 寻根究底地检验, 充满于\nvi. 出谜；英英释义：n. a difficult problem\nn. a coarse sieve (as for gravel)\nv. pierce with many holes\nv. set a difficult problem or riddle；词形变化：d:riddled/s:riddles/p:riddled/i:riddling/3:riddles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8e15a01fce1ba899f4',NULL,'ridge','/ridʒ/','n. 脊, 山脊, 山脉\n[医] 嵴, 脊, 棱线；英英释义：n. a long narrow natural elevation or striation\nn. any long raised strip\nn. a long narrow natural elevation on the floor of the ocean\nn. a long narrow range of hills；词形变化：s:ridges/i:ridging/p:ridged/3:ridges/d:ridged','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
