INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4aff9c143c27f09d30',NULL,'rifle','/''raifl/','n. 来复枪, 步枪\nvt. 用步枪射击, 抢夺\nvi. (抱有不良意图)迅速翻查；英英释义：n. a shoulder firearm with a long barrel and a rifled bore\nv. go through in search of something; search through someone''s belongings in an unauthorized way；词形变化：s:rifles/p:rifled/i:rifling/d:rifled/3:rifles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c209fe73d698ea3741',NULL,'rigid','/''ridʒid/','a. 坚硬的, 刚性的, 严格的, 精密的, 刻板的；英英释义：s. incapable of or resistant to bending\ns. incapable of compromise or flexibility\na. designating an airship or dirigible having a form maintained by a stiff unyielding frame or structure','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
