INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e042d44fbc46d450f5',NULL,'rim','/rim/','n. 边, 轮缘, 框\nvt. 镶边, 为...装边\nvi. 形成边缘；英英释义：n. the shape of a raised edge of a more or less circular object\nn. (basketball) the hoop from which the net is suspended\nn. the outer part of a wheel to which the tire is attached\nv. run around the rim of；词形变化：s:rims/p:rimmed/d:rimmed/i:rimming/3:rims','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_09933254d54b3c14ba',NULL,'riot','/''raiәt/','n. 暴动, 喧闹, 放纵\nvi. 发动, 暴动, 纵情, 放荡\nvt. 浪费, 挥霍；英英释义：n. a public act of violence by an unruly mob\nv. take part in a riot; disturb the public peace by engaging in a riot；词形变化：s:riots/p:rioted/i:rioting/3:riots/d:rioted','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6cf733bc7259cd84cb',NULL,'rip','/rip/','n. 裂痕, 破绽, 拉裂, 浪子, 巨浪\nvi. 被拉开, 裂开, 猛冲\nvt. 撕, 扯, 劈；英英释义：n. an opening made forcibly as by pulling apart\nn. a stretch of turbulent water in a river or the sea caused by one current flowing into or across another current\nv. move precipitously or violently\nv. cut (wood) along the grain；词形变化：p:ripped/d:ripped/i:ripping/3:rips/s:rips','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_efb7ccf4c8ce957a6c',NULL,'ripe','/raip/','a. 成熟的, 熟练的, 成年的\n[医] 成熟的；英英释义：a. fully developed or matured and ready to be eaten or used\ns. fully prepared or eager\ns. at the highest point of development especially in judgment or knowledge；词形变化：t:ripest/r:riper','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_57a370d1acaae09d70',NULL,'rise','/raiz/','n. 上升, 增加, 上涨, 高地, 升高, 出现\nvi. 升起, 起身, 起立, 上升, 上涨, 增长, 高耸, 起义, 浮现\nvt. 使飞起；英英释义：n. a growth in strength or number or importance\nn. the act of changing location in an upward direction\nn. a movement upward\nn. an increase in cost；词形变化：p:rose/i:rising/d:risen/s:rises/3:rises','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e8d7eaf2a51200b01b',NULL,'risk','/risk/','n. 冒险, 危险, 保险额\nvt. 冒...的危险, 冒险干；英英释义：n. a venture undertaken without regard to possible loss or injury\nn. the probability of becoming infected given that exposure to an infectious agent has occurred\nn. the probability of being exposed to an infectious agent\nv. expose to a chance of loss or damage；词形变化：s:risks/i:risking/p:risked/3:risks/d:risked','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5a62f73d677e4efdfb',NULL,'ritual','/''ritʃuәl/','n. 仪式, 典礼, 宗教仪式\na. 仪式的, 依仪式进行的；英英释义：n. any customary observance or practice\nn. the prescribed procedure for conducting religious ceremonies\nn. stereotyped behavior\na. of or relating to or characteristic of religious rituals；词形变化：s:rituals','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_85344481ed25dd1529',NULL,'rival','/''raivl/','n. 对手, 竞争者\na. 竞争的；英英释义：n. the contestant you hope to defeat\nv. be the rival of, be in competition with；词形变化：s:rivals/p:rivalled/3:rivals/i:rivalling/d:rivalled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_45b8e7b3f70640f19e',NULL,'roar','/rɒ:/','n. 吼, 咆哮, 轰鸣\nvi. 吼, 大声说出, 叫喊, 喧闹\nvt. 呼喊, 使轰鸣；英英释义：n. the sound made by a lion\nv. make a loud noise, as of wind, water, or vehicles\nv. act or proceed in a riotous, turbulent, or disorderly way\nv. laugh unrestrainedly and heartily；词形变化：p:roared/i:roaring/3:roars/s:roars/d:roared','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e1d58088bd282573de',NULL,'roast','/rәust/','n. 烤肉, 烘烤, 嘲笑\na. 烘烤的, 烤过的\nvt. 烤, 炙, 烘焙, 嘲笑\nvi. 烤, 炙, 烘焙；英英释义：n. a piece of meat roasted or for roasting and of a size for slicing into more than one portion\nv. cook with dry heat, usually in an oven\ns. (meat) cooked by dry heat in an oven；词形变化：i:roasting/d:roasted/p:roasted/s:roasts/3:roasts/r:roaster','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e11efb93a9d1c72646',NULL,'rob','/rɒb/','v. 抢夺, 抢掠, 剥夺；英英释义：v. take something away by force or without the consent of the owner；词形变化：d:robbed/p:robbed/i:robbing/3:robs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0a9c5a72eacca05525',NULL,'robe','/rәub/','n. 宽松长袍, 礼服, 披肩, 覆盖物\nv. (给)穿长袍；英英释义：n. any loose flowing garment；词形变化：s:robes/p:robed/d:robed/i:robing/3:robes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7f368a722ca40368d6',NULL,'robot','/''rәubәt/','n. 机械人, 自动机械, 机械般工作的人\n[计] 机器人; 自动机；英英释义：n a mechanism that can move automatically；词形变化：s:robots','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('c3f01eeb-cd52-41f1-9696-8159364168c0',NULL,'robust','/rәu''bʌst/','a. 健康的, 强健的, 要用力气的, 坚定的, 粗野的\n[计] 健壮性；英英释义：a. sturdy and strong in form, constitution, or construction\ns. strong enough to withstand or overcome intellectual challenges or adversity\ns. rough and crude；词形变化：r:robuster','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_02675cc3824d2a0acd',NULL,'rock','/rɒk/','n. 岩石, 岩礁, 石头, 基石, 暗礁, 摇动, 摇滚乐\nvt. 摇摆, 摇动, 使摇晃, 使动摇\nvi. 摇, 摇动；英英释义：n. a lump or mass of hard consolidated mineral matter\nn. material consisting of the aggregate of minerals like those making up the Earth''s crust\nn. United States gynecologist and devout Catholic who conducted the first clinical trials of the oral contraceptive pill (1890-1984)\nn. (figurative) someone who is strong and stable and dependable；词形变化：s:rocks/i:rocking/p:rocked/d:rocked/3:rocks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5f552daf539c7e6c8a',NULL,'rocket','/''rɒkit/','n. 火箭, 烟火\nvi. 急升, 猛涨, 飞驰\nvt. 用火箭运载；英英释义：n. any vehicle self-propelled by a rocket engine\nn. a jet engine containing its own propellant and driven by reaction propulsion\nn. erect European annual often grown as a salad crop to be harvested when young and tender\nn. propels bright light high in the sky, or used to propel a lifesaving line or harpoon；词形变化：s:rockets/d:rocketed/p:rocketed/3:rockets/i:rocketing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1805d360ec8835964a',NULL,'rod','/rɒd/','n. 竿, 笞鞭, 小枝\n[化] 棒；英英释义：n. a long thin implement made of metal or wood\nn. any rod-shaped bacterium\nn. a visual receptor cell that is sensitive to dim light；词形变化：s:rods/i:rodding','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3072eb572e5e72ed64',NULL,'role','/rәul/','n. 角色, 职责, 任务\n[医] 作用, 功用；英英释义：n. normal or customary activity of a person in a particular social setting；词形变化：s:roles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_866c9683435647b7e0',NULL,'roll','/rәul/','n. 卷, 滚动, 名单, 案卷, 压路机\nvi. 滚, 滚动, 飘流, 起伏, 卷, 绕\nvt. 使滚动, 卷, 绕；英英释义：n. a list of names\nn. photographic film rolled up inside a container to protect it from light\nn. anything rolled up in cylindrical form\nn. walking with a swaying gait；词形变化：p:rolled/s:rolls/i:rolling/d:rolled/3:rolls','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fd8c1b3503c3998f6c',NULL,'romance','/rәu''mæns/','n. 冒险故事, 浪漫史, 传奇文学\nvi. 写传奇, 作空想, 虚构；英英释义：n. the group of languages derived from Latin\nn. a novel dealing with idealized events remote from everyday life\nv. have a love affair with\nv. tell romantic or exaggerated lies；词形变化：s:romances/i:romancing/d:romanced/p:romanced/3:romances','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a8b5b77927d904f811',NULL,'romantic','/rәu''mæntik/','a. 浪漫的, 风流的, 传奇性的, 夸大的, 空想的, 浪漫派的；英英释义：n. a soulful or amorous idealist\na. belonging to or characteristic of Romanticism or the Romantic Movement in the arts；词形变化：s:romantics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ebb71eaf43ddb9b7e8',NULL,'roof','/ru:f/','n. 屋顶, 室顶\nvt. 给...盖屋顶, 遮蔽；英英释义：n. a protective covering that covers or forms the top of a building\nn. protective covering on top of a motor vehicle\nn. the inner top surface of a covered area or hollow space\nv. provide a building with a roof; cover a building with a roof；词形变化：s:roofs/d:roofed/i:roofing/p:roofed/3:roofs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_24e0f7e209d946d490',NULL,'root','/ru:t/','n. 根, 根本, 根源, 基础, 底部\nvt. 使扎根, 使固定, 根除, 肃清, 搜出, 用鼻拱\nvi. 生根, 固定, 源于, 用鼻拱土, 寻找, 捧场, 支持；英英释义：n. (botany) the usually underground organ that lacks buds or leaves or nodes; absorbs water and mineral salts; usually it anchors the plant to the ground\nn. (linguistics) the form of a word after all affixes are removed\nn. a number that, when multiplied by itself some number of times, equals a given number\nn. the part of a tooth that is embedded in the jaw and serves as support；词形变化：s:roots/d:rooted/i:rooting/p:rooted/3:roots','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ea6fd093fd40e61f31',NULL,'rope','/rәup/','n. 绳, 索, 粗绳, 绞索, 决窍\nvt. 捆, 缚, 绑, 圈起, 以绳将...系住\nvi. 拧成绳状；英英释义：n. a strong line\nv. fasten with a rope；词形变化：s:ropes/d:roped/i:roping/p:roped/3:ropes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d73420e3bf01774be2',NULL,'rose','/rәuz/','n. 玫瑰, 蔷薇, 玫瑰色\na. 玫瑰色的, 玫瑰花的\nvt. 使成玫瑰色\nrise的过去式；英英释义：n. any of many shrubs of the genus Rosa that bear roses\nn. a dusty pink color\ns. of something having a dusty purplish pink color；词形变化：0:rise/1:pd/s:roses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bbb6186cc319c3aaee',NULL,'rot','/rɒt/','n. 腐烂, 腐蚀, 败坏\nvi. 腐烂, 烂, 堕落, 憔悴\nvt. 使腐烂, 使腐朽, 使堕落；英英释义：n a state of decay usually accompanied by an offensive odor\nn (biology) the process of decay caused by bacterial or fungal action\nn unacceptable behavior (especially ludicrously false statements)\nv break down\nv become physically weaker；词形变化：d:rotted/i:rotting/3:rots/p:rotted/s:rots','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_936715edb9334b8043',NULL,'rotary','/''rәutәri/','a. 旋转的, 轮流的\nn. 旋转式机器；英英释义：a. relating to or characterized by rotation；词形变化：s:rotaries','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8a23f3fa7beeceee6f',NULL,'rotate','/''rәuteit/','a. 辐状的\nvt. 使旋转, 使转动, 使轮流\nvi. 旋转, 循环\n[计] 旋转；英英释义：v. exchange on a regular basis\nv. perform a job or duty on a rotating basis\nv. cause to turn on an axis or center；词形变化：i:rotating/d:rotated/3:rotates/p:rotated/s:rotates','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_83025ccdfad9cb365b',NULL,'rotten','/''rɒtn/','a. 腐烂的, 恶臭的, 堕落的, 风化的, 虚弱的\n[经] 腐烂的, 堕落的；英英释义：s. having decayed or disintegrated; usually implies foulness','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_976965469a29d97e44',NULL,'rough','/rʌf/','n. 粗糙的东西, 毛坯, 未加工品, 梗概, 草图, 暴徒, 艰难\na. 粗糙的, 粗暴的, 蓬乱的, 草率的, 大致的, 简陋的, 暴风雨的, 艰难的\nvt. 使粗糙, 使不平, 使蓬乱, 粗制, 草拟, 粗暴对待, 对...动粗\nvi. 变粗糙\nadv. 粗糙地, 粗暴地；英英释义：n. the part of a golf course bordering the fairway where the grass is not cut short\na. having or caused by an irregular surface\ns. (of persons or behavior) lacking refinement or finesse\na. of the margin of a leaf shape; having the edge cut or fringed or scalloped；词形变化：r:rougher/t:roughest/d:roughed/s:roughs/i:roughing/p:roughed/3:roughs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b22e5724d12f06a4a0',NULL,'roughly','/''rʌfli/','adv. 概略地, 粗糙地, 粗暴地；英英释义：r. with roughness or violence (`rough'' is an informal variant for `roughly'')\nr. with rough motion as over a rough surface','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0a1216c5327c763627',NULL,'roundabout','/''raundә.baut/','a. 迂回的, 委婉的\nn. 迂回路线；英英释义：n a road junction at which traffic streams circularly around a central island\nn a large, rotating machine with seats for children to ride or amusement\ns marked by obliqueness or indirection in speech or conduct\ns deviating from a straight course；词形变化：s:roundabouts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9b8925d5d6c42bbf6f',NULL,'rouse','/rauz/','n. 觉醒, 奋起, 干杯\nvt. 唤醒, 鼓舞, 激动, 使振奋, 惊起\nvi. 醒来, 奋起；英英释义：v become active\nv force or drive out\nv cause to be agitated, excited, or roused\nv cause to become awake or conscious；词形变化：d:roused/p:roused/i:rousing/3:rouses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9a528d13dab5529239',NULL,'route','/ru:t/','n. 路径, 途径, 路线\nvt. 确定路线, 按规定路线发送\n[计] 传递, 路由设定程序；英英释义：v. send documents or materials to appropriate destinations\nv. send via a specific route\nv. divert in a specified direction；词形变化：s:routes/i:routing/p:routed/3:routes/d:routed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_eafceeb766cbbfa618',NULL,'routine','/ru:''ti:n/','n. 常规, 日常工作, 惯例, 例行公事\na. 日常的, 常规的\n[计] 例程；英英释义：n. an unvarying or habitual method or procedure\nn. a set sequence of steps, part of larger computer program；词形变化：s:routines','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3cd3706daaede05687',NULL,'row','/rәu. rau/','n. 排, 行, 街道, 划船, 吵闹\nvt. 使成排, 划, 划船, 参加(赛船), 痛骂\nvi. 划船, 划动, 争吵\n[计] 行；英英释义：n. an arrangement of objects or people side by side in a line\nn. a long continuous strip (usually running horizontally)\nn. a linear array of numbers, letters, or symbols side by side\nn. a continuous chronological succession without an interruption；词形变化：s:rows/p:rowed/d:rowed/i:rowing/3:rows','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_df012f77c01e22e744',NULL,'royal','/''rɒiәl/','n. 王室, 皇族\na. 王室的, 皇家的, 盛大的, 庄严的；英英释义：n. a sail set next above the topgallant on a royal mast\nn. stag with antlers of 12 or more branches\na. of or relating to or indicative of or issued or performed by a king or queen or other monarch\na. established or chartered or authorized by royalty；词形变化：s:royals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7f6eb7c8e637e8558a',NULL,'royalty','/''rɒiәlti/','n. 皇室, 王族成员, 王权, 特权阶层, 庄严\n[经] 特许权, 使用费, 使用税；英英释义：n. payment to the holder of a patent or copyright or resource for the right to use their property\nn. royal persons collectively；词形变化：s:royalties','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_adb1fb7011cc04c3d3',NULL,'rub','/rʌb/','n. 摩擦, 困难, 障碍, 磨损处\nvt. 擦, 搓, 摩擦, 惹怒\nvi. 摩擦, 擦破；英英释义：n. the act of rubbing or wiping\nv. move over something with pressure\nv. cause friction\nv. scrape or rub as if to relieve itching；词形变化：p:rubbed/i:rubbing/d:rubbed/3:rubs/s:rubs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8c2fc53b7e0bcf9833',NULL,'rubber','/''rʌbә/','n. 橡皮, 橡胶, 做摩擦动作的人, 按摩师, 决胜盘\nvt. 用橡胶制造, 涂橡胶于；英英释义：n. an elastic material obtained from the latex sap of trees (especially trees of the genera Hevea and Ficus) that can be vulcanized and finished into a variety of products\nn. any of various synthetic elastic materials whose properties resemble natural rubber\ns. returned for lack of funds；词形变化：s:rubbers/i:rubbering/p:rubbered/3:rubbers/d:rubbered','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f992bc06c68193fed3',NULL,'rubbish','/''rʌbiʃ/','n. 废物, 垃圾, 胡说；英英释义：n. worthless material that is to be disposed of\nv. attack strongly；词形变化：p:rubbished/d:rubbished/i:rubbishing/3:rubbishes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9c2ff4274fa65ebd3b',NULL,'ruby','/''ru:bi/','n. 红宝石, 深红色\na. 红宝石色的, 深红色的\nvt. 使带红宝石色；英英释义：n. a transparent piece of ruby that has been cut and polished and is valued as a precious gem\nn. a transparent deep red variety of corundum; used as a gemstone and in lasers；词形变化：s:rubies','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_605fa7606daa8170e7',NULL,'rude','/ru:d/','a. 粗鲁无礼的, 粗陋的, 粗暴的, 原始的, 未开化的, 大略的, 崎岖不平的, 狂暴的；英英释义：s socially incorrect in behavior\ns (of persons) lacking in refinement or grace\na lacking civility or good manners\ns (used especially of commodities) being unprocessed or manufactured using only simple or minimal processes\ns belonging to an early stage of technical development; characterized by simplicity and (often) crudeness；词形变化：r:ruder/t:rudest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_85cc84ae4e4ab6f609',NULL,'rug','/rʌg/','n. 小块地毯, 揭露某人；英英释义：n. floor covering consisting of a piece of thick heavy fabric (usually with nap or pile)；词形变化：s:rugs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d9ffbf91655db92ca8',NULL,'ruin','/ruin/','n. 毁灭, 推翻, 废墟\nvi. 毁灭, 衰败, 破坏, 破产, 堕落\nvt. 使毁灭, 毁坏, 使破产；英英释义：n. an irrecoverable state of devastation and destruction\nn. a ruined building\nn. an event that results in destruction\nv. destroy or cause to fail；词形变化：s:ruins/3:ruins/i:ruining/p:ruined/d:ruined','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2050d8ccc4d67e6d69',NULL,'rule','/ru:l/','n. 规则, 统治, 控制, 支配, 规律, 标准, 章程, 破折号, 铅线\nvt. 规定, 统治, 管理, 控制, 支配, 裁决\nvi. 统治, 管辖, 裁定\n[计] 规则, 水线；英英释义：n. a principle or condition that customarily governs behavior\nn. prescribed guide for conduct or action\nn. (linguistics) a rule describing (or prescribing) a linguistic practice\nn. the duration of a monarch''s or government''s power；词形变化：s:rules/d:ruled/p:ruled/3:rules/i:ruling','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_418cd7d70d1653ff5a',NULL,'ruler','/''ru:lә/','n. 统治者, 管理者, 尺, 直尺\nn. 划线板\n[计] 标尺；英英释义：n. a person who rules or commands；词形变化：s:rulers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
