INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_57352d07bfcebe5927',NULL,'rural','/''ruәrәl/','a. 乡下的, 田园的, 乡村风味的\n[法] 农村的, 乡村的, 有关农业的；英英释义：a. living in or characteristic of farming or country life\na. of or relating to the countryside as opposed to the city','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fa726f7daf2d11dd90',NULL,'rush','/rʌʃ/','n. 匆促, 冲进, 急流, 灯心草\nvi. 冲, 奔, 闯, 赶紧, 匆促行事, 涌现\nvt. 使冲, 匆忙地做, 突袭, 飞跃, 用灯心草做\na. 紧急的；英英释义：n. a sudden forceful flow\nn. grasslike plants growing in wet places and having cylindrical often hollow stems\nn. physician and American Revolutionary leader; signer of the Declaration of Independence (1745-1813)\nn. a sudden burst of activity；词形变化：i:rushing/p:rushed/d:rushed/s:rushes/3:rushes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fa99bc2b357c801548',NULL,'rust','/rʌst/','n. 锈, 生锈, 衰退\nvi. 生锈, 衰退\nvt. 使生锈, 腐蚀；英英释义：n. a red or brown oxide coating on iron or steel caused by the action of oxygen and moisture\nn. a plant disease that produces a reddish-brown discoloration of leaves and stems; caused by various rust fungi\nn. the formation of reddish-brown ferric oxides on iron by low-temperature oxidation in the presence of water\nn. any of various fungi causing rust disease in plants；词形变化：i:rusting/d:rusted/3:rusts/s:rusts/p:rusted','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
