INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3fc0764de2dade12ca',NULL,'sack','/sæk/','n. 麻布袋, 洗劫\nvt. 把...装入袋, 洗劫；英英释义：n. a bag made of paper or plastic for holding customer''s purchases\nn. the quantity contained in a sack\nn. any of various light dry strong white wine from Spain and Canary Islands (including sherry)\nn. a woman''s full loose hiplength jacket；词形变化：d:sacked/s:sacks/p:sacked/i:sacking/3:sacks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_45ba0eea5d6ea0ad8d',NULL,'sacred','/''seikrid/','a. 神圣的, 献给上帝的, 庄严的, 祭祀的\n[法] 神圣的, 不可侵犯的；英英释义：a. concerned with religion or religious purposes\ns. worthy of respect or dedication\ns. (often followed by `to'') devoted exclusively to a single use or purpose or person','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
