INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f027d824d82c56de31',NULL,'segment','/''segmәnt/','n. 片段, 部分, 分节, 段\nv. 分割, 分裂\n[计] 段；英英释义：n. one of the parts into which something naturally divides\nv. divide into segments\nv. divide or split up；词形变化：s:segments/d:segmented/i:segmenting/p:segmented/3:segments','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_15d17ce6406433d99e',NULL,'segregate','/''segrigeit/','a. 分离的, 被隔离的\nvi. 分离, 隔离, 分凝\nvt. 使分离, 使隔离；英英释义：n. someone who is or has been segregated\nv. separate by race or religion; practice a policy of racial segregation\nv. divide from the main body or mass and collect；词形变化：d:segregated/i:segregating/3:segregates/p:segregated','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
