INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b45bc26e0c79c85c2a',NULL,'sex','/seks/','n. 性别, 性欲\nvt. 区别...的性别, 引起...的性欲；英英释义：n. either of the two categories (male or female) into which most organisms are divided\nn. all of the feelings resulting from the urge to gratify sexual impulses\nn. the properties that distinguish organisms on the basis of their reproductive roles\nv. tell the sex (of young chickens)；词形变化：s:sexes/i:sexing/p:sexed/3:sexes/d:sexed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6b69811ed2b6e16dd2',NULL,'shabby','/''ʃæbi/','a. 衣衫褴褛的, 低劣的, 破旧的, 吝啬的, 卑鄙的；英英释义：s. mean and unworthy and despicable；词形变化：r:shabbier/t:shabbiest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a9d98a58cbf8ac2ed6',NULL,'shade','/ʃeid/','n. 荫, 阴暗, 遮光物, 灯罩, 帘, 浓淡, 微量, 底纹\nvi. 渐变\nvt. 使阴暗, 使渐变, 遮蔽, 微减\n[计] 底纹；英英释义：n. relative darkness caused by light rays being intercepted by an opaque body\nn. a quality of a given color that differs slightly from another color\nn. protective covering that protects something from direct sunlight\nn. a position of relative inferiority；词形变化：s:shades/i:shading/d:shaded/p:shaded/3:shades','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_711d1d545a4f729b21',NULL,'shadow','/''ʃædәu/','n. 阴影, 荫, 影子, 影像, 阴暗, 幽灵, 少许, 隐蔽处, 庇护\nvt. 遮蔽, 使朦胧, 预示, 尾随\nvi. 渐变, 变阴暗\n[计] 阴影；英英释义：n. shade within clear boundaries\nn. a premonition of something adverse\nn. refuge from danger or observation\nn. a dominating and pervasive presence；词形变化：d:shadowed/i:shadowing/p:shadowed/s:shadows/3:shadows','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f28c9fe2b73dd20493',NULL,'shady','/''ʃeidi/','a. 荫凉的, 成荫的, 阴暗的, 隐蔽的\n[法] 成问题的, 令人怀疑的；英英释义：s. filled with shade；词形变化：r:shadier/t:shadiest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_74c6aa0dc6945ba9ab',NULL,'shaft','/ʃæft/','n. 轴, 箭杆, 矛, 矿井\nvt. 装杆于, 利用；英英释义：n. a line that forms the length of an arrow pointer\nn. a long rod or pole (especially the handle of an implement or the body of a weapon like a spear or arrow)\nn. a vertical passageway through a building (as for an elevator)\nn. (architecture) upright consisting of the vertical part of a column；词形变化：s:shafts/i:shafting/p:shafted/d:shafted/3:shafts','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_33ddebc7168324a661',NULL,'shake','/ʃeik/','n. 摇动, 震动\nvt. 摇动, 动摇, 使震动, 挥舞\nvi. 震动, 发抖, 动摇；英英释义：v. move or cause to move back and forth\nv. move with or as if with a tremor\nv. undermine or cause to waver\nv. get rid of；词形变化：p:shook/i:shaking/d:shaken/3:shakes/s:shakes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0a560d20406cc20c3b',NULL,'shallow','/''ʃælәu/','n. 水浅的地方, 浅滩\na. 浅的, 肤浅的\nv. (使)变浅；英英释义：v. make shallow\nv. become shallow\na. lacking physical depth; having little spatial extension downward or inward from an outer surface or backward or outward from a center\na. not deep or strong; not affecting one deeply；词形变化：s:shallows/r:shallower/t:shallowest/p:shallowed/i:shallowing/3:shallows/d:shallowed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cc78fb36ab3f523ec8',NULL,'sham','/ʃæm/','n. 假, 赝品, 骗子, 哄骗\na. 假的, 伪造的\nvt. 假装, 冒充\nvi. 装假；英英释义：n something that is a counterfeit; not what it seems to be\nn a person who makes deceitful pretenses\nv make a pretence of\nv make believe with the intent to deceive\ns adopted in order to deceive；词形变化：s:shams/i:shamming/p:shammed/3:shams/d:shammed','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7c5beb814a947ba38c',NULL,'shame','/ʃeim/','n. 羞耻, 羞愧, 耻辱\nvt. 使羞愧, 侮辱；英英释义：n. a painful emotion resulting from an awareness of inadequacy or guilt\nn. a state of dishonor\nv. compel through a sense of shame\nv. cause to be ashamed；词形变化：d:shamed/3:shames/p:shamed/i:shaming/s:shames','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_db3d216cb723e775ad',NULL,'shampoo','/ʃæm''pu:/','n. 洗头, 洗发剂\nvt. 洗头, 洗发；英英释义：n. cleansing agent consisting of soaps or detergents used for washing the hair\nn. the act of washing your hair with shampoo\nv. use shampoo on (hair)；词形变化：s:shampoos/i:shampooing/p:shampooed/3:shampoos/d:shampooed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a2b76a97399a7709c2',NULL,'shape','/ʃeip/','n. 形状, 形态, 外形, 形式, 身材\nvt. 定形, 使成形, 塑造, 计划, 使符合\nvi. 成形, 形成, 成长\n[计] 形状；英英释义：n. any spatial attributes (especially as defined by outline)\nn. the spatial arrangement of something as distinct from its substance\nn. a concrete representation of an otherwise nebulous concept\nv. make something, usually for a specific function；词形变化：s:shapes/d:shaped/i:shaping/p:shaped/3:shapes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_700df62f5f21c6a85f',NULL,'share','/ʃєә/','n. 部分, 参与, 一份, 参股, 份额\nvt. 均分, 分担, 分享, 分配, 共有\nvi. 分享\n[计] 共享; DOS外部命令:在网络或多工系统中提供文件共享\n文件锁定及检测磁盘更动和对超过32MB硬盘分区的支持；英英释义：n. assets belonging to or due to or contributed by an individual person or group\nn. any of the equal portions into which the capital stock of a corporation is divided and ownership of which is evidenced by a stock certificate\nv. have in common\nv. use jointly or in common；词形变化：s:shares/d:shared/i:sharing/p:shared/3:shares','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_18d90ae32f0e1937e6',NULL,'shark','/ʃɑ:k/','n. 鲨鱼, 骗子\nv. 诈骗；英英释义：n. any of numerous elongate mostly marine carnivorous fishes with heterocercal caudal fins and tough skin covered with small toothlike scales\nn. a person who is ruthless and greedy and dishonest\nn. a person who is unusually skilled in certain ways\nv. play the shark; act with trickery；词形变化：s:sharks/i:sharking/p:sharked/3:sharks/d:sharked','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8687a0d24d8667b8d9',NULL,'sharp','/ʃɑ:p/','n. 半升音调, 利刃, 骗子\na. 锋利的, 明显的, 敏锐的, 急剧的, 尖刻的, 严厉的, 刺耳的, 精明的\nadv. 锐利地, 急速地；英英释义：n. a musical notation indicating one half step higher than the note named\nn. a long thin sewing needle with a sharp point\ns. harsh\na. keenly and painfully felt; as if caused by a sharp edge or point；词形变化：s:sharps','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e69b12d3e411bb4300',NULL,'shatter','/''ʃætә/','n. 碎片, 粉碎, 落叶, 喷洒\nvt. 打碎, 使散开, 粉碎, 破坏\nvi. 粉碎, 损坏, 脱落；英英释义：v. break into many pieces\nv. damage or destroy\nv. cause to break into many pieces；词形变化：d:shattered/p:shattered/i:shattering/3:shatters','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ba88a1f7bf2dcbe955',NULL,'shave','/ʃeiv/','n. 修面, 刮胡子, 幸免, 剃刀\nvt. 修面, 剃, 修剪, 掠过\nvi. 刮脸, 勉强通过；英英释义：n. the act of removing hair with a razor\nv. remove body hair with a razor\nv. cut closely\nv. cut the price of；词形变化：d:shaved/i:shaving/p:shaved/3:shaves/s:shaves','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_490ca761bde540e540',NULL,'shear','/ʃiә/','n. 修剪, 剪下的东西, 大剪刀, 切变, 剪切机, 切\nvt. 修剪, 割, 剥夺, 横越, 削剪\nvi. 剪, 修剪, 剪羊毛, 切断；英英释义：n. (physics) a deformation of an object in which parallel planes remain parallel but are shifted in a direction parallel to themselves\nn. a large edge tool that cuts sheet metal by passing a blade through it\nv. cut with shears\nv. cut or cut through with shears；词形变化：s:shears/d:shorn/i:shearing/p:sheared/3:shears','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9ca93839752eaaf035',NULL,'shed','/ʃed/','n. 车棚, 小屋, 脱落之物, 分水岭\nvt. 使流出, 放射, 脱落, 散发, 摆脱\nvi. 流出, 散布, 脱落；英英释义：n. an outbuilding with a single story; used for shelter or storage\nv. get rid of\nv. cast off hair, skin, horn, or feathers；词形变化：s:sheds/d:shed/0:shed/1:dp/i:shedding/p:shed/3:sheds','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e132f2e995e7bffb7e',NULL,'sheer','/ʃiә/','a. 绝对的, 全然的, 纯粹的, 透明的, 峻峭的\nvi. 偏转, 偏航\nvt. 使急转向, 使偏航\nadv. 完全, 全然, 峻峭\nn. 偏航；英英释义：v. cause to sheer\nr. straight up or down without a break\nr. directly；词形变化：s:sheers/p:sheered/i:sheering/3:sheers/d:sheered','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3b061c6acf8cc695f5',NULL,'sheet','/ʃi:t/','n. 床单, 张, 纸张, 印刷品, 裹尸布, 薄片\nvt. 盖上被单, 遍布\nvi. 大片落下\na. 片状的, 成薄片的\n[计] 工作表；英英释义：n. any broad thin expanse or surface\nn. paper used for writing or printing\nn. bed linen consisting of a large rectangular piece of cotton or linen cloth; used in pairs\nn. a flat artifact that is thin relative to its length and width；词形变化：s:sheets/d:sheeted/p:sheeted/i:sheeting/3:sheets','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_188b18ded8d9057eff',NULL,'shelf','/ʃelf/','n. 架子, 搁板\n[化] 架子；英英释义：n. a support that consists of a horizontal surface for holding objects；词形变化：s:shelves','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_adbf35d6aef5beddb2',NULL,'shell','/ʃel/','n. 贝壳, 壳, 外形, 炮弹\nvt. 去壳, 脱落, 炮轰\nvi. 剥落, 脱壳\n[计] 外壳; DOS内部命令:指定命令行处理程序；英英释义：n. ammunition consisting of a cylindrical metal casing containing an explosive charge and a projectile; fired from a large gun\nn. the material that forms the hard outer covering of many animals\nn. the hard usually fibrous outer layer of some fruits especially nuts\nn. the exterior covering of a bird''s egg；词形变化：s:shells/i:shelling/d:shelled/p:shelled/3:shells','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
