INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_56cd31a45feb405273',NULL,'silence','/''sailәns/','n. 沉默, 无声, 静寂, 湮没, 无声息\nvt. 使缄默\ninterj. 安静；英英释义：n. the state of being silent (as when no one is speaking)\nn. the absence of sound\nv. keep from expression, for example by threats or pressure；词形变化：d:silenced/p:silenced/i:silencing/s:silences/3:silences','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
