INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c19718f8e15367734d',NULL,'silicon','/''silikәn/','n. 硅\n[化] 硅Si；英英释义：n. a tetravalent nonmetallic element; next to oxygen it is the most abundant element in the earth''s crust; occurs in clay and feldspar and granite and quartz and sand; used as a semiconductor in transistors；词形变化：d:siliconed/p:siliconed/i:siliconing','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
