INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_869ecb23a2adc3e26f',NULL,'simplicity','/sim''plisiti/','n. 单纯, 简朴, 朴素, 坦率, 天真\n[计] 简明性；英英释义：n. the quality of being simple or uncompounded\nn. a lack of penetration or subtlety\nn. absence of affectation or pretense；词形变化：s:simplicities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
