INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5c90a1875e6c00208a',NULL,'sin','/sin/','n. 罪, 犯罪, 过失, 失礼\nv. 犯；英英释义：n. estrangement from god\nn. an act that is regarded by theologians as a transgression of God''s will\nn. (Akkadian) god of the Moon; counterpart of Sumerian Nanna\nn. the 21st letter of the Hebrew alphabet；词形变化：s:sins/d:sinned/i:sinning/p:sinned/3:sins','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
