INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3f82c4286b32a3250b',NULL,'singular','/''siŋgjulә/','n. 单数\na. 异常的, 单一的；英英释义：n. the form of a word that is used to denote a singleton\ns. being a single and separate person or thing\na. composed of one member, set, or kind\na. grammatical number category referring to a single item or unit；词形变化：s:singulars','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0e7cbb07968dddae3d',NULL,'sink','/siŋk/','n. 藏垢的场所, 沟渠, 污水槽\nvi. 下沉, 沉没, 下陷, 减弱, 衰退, 消沉, 堕落, 渗透\nvt. 使低落, 使下沉, 陷于, 投入(资金等), 挖掘；英英释义：n. plumbing fixture consisting of a water basin fixed to a wall or floor and having a drainpipe\nn. (technology) a process that acts to absorb or remove energy or a substance from a system\nv. fall or descend to a lower place or level\nv. cause to sink；词形变化：p:sank/d:sunk/i:sinking/s:sinks/3:sinks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1ce082da725489f3a7',NULL,'sip','/sip/','n. 啜饮, 小口喝, 抿\nvi. 啜饮\nvt. 啜\n[计] 单列直插式组件；英英释义：n. a small drink\nv. drink in sips；词形变化：p:sipped/i:sipping/s:sips/3:sips/d:sipped','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_220338aef398f7439f',NULL,'siren','/''saiәrin/','n. 女海妖, 妖女, 警报器, 汽笛, 迷人的美女\na. 诱惑的\nvi. 响着警报器前进；英英释义：n. a sea nymph (part woman and part bird) supposed to lure sailors to destruction on the rocks where the nymphs lived\nn. a warning signal that is a loud wailing sound\nn. an acoustic device producing a loud often wailing sound as a signal or warning\nn. eellike aquatic North American salamander with small forelimbs and no hind limbs; have permanent external gills；词形变化：s:sirens','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d0e0fe2fa19ebd4ae6',NULL,'site','/sait/','n. 位置, 场所, 地点\nvt. 给...择址；英英释义：n. the piece of land on which something is located (or is to be located)\nn. physical position in relation to the surroundings；词形变化：s:sites/d:sited/i:siting/p:sited/3:sites','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e2f1d2343679e88660',NULL,'situated','/''sitjueitid/','a. 位于...的, 坐落在...的, 处于某种境地的\n[法] 坐落...的, 位于...的, 处于某种境地的；英英释义：v determine or indicate the place, site, or limits of, as if by an instrument or by a survey\nv put (something somewhere) firmly\ns situated in a particular spot or position；词形变化：1:dp/0:situate/d:situated','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0cb47ea43713b2b243',NULL,'situation','/.sitju''eiʃәn/','n. 情形, 境遇, 位置\n[医] 情境, 处境；英英释义：n. the general state of things; the combination of circumstances at a given time\nn. a condition or position in which you find yourself\nn. a complex or critical or unusual difficulty；词形变化：s:situations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_230b5d9e230a72ebe2',NULL,'skate','/skeit/','n. 溜冰, 冰鞋\nvi. 滑冰, 滑过；英英释义：n. sports equipment that is worn on the feet to enable the wearer to glide along and to be propelled by the alternate actions of the legs\nn. large edible rays having a long snout and thick tail with pectoral fins continuous with the head; swim by undulating the edges of the pectoral fins\nv. move along on skates；词形变化：i:skating/s:skates/p:skated/3:skates/d:skated','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e70dfea0c03e09980f',NULL,'skeleton','/''skelәtn/','n. 骨骼, 骨瘦如柴的人, 梗概, 骨干, 残骸\na. 骨骼的, 概略的, 基层的, 骨干的\n[计] 骨架；英英释义：n. something reduced to its minimal form\nn. a scandal that is kept secret\nn. the internal supporting structure that gives an artifact its shape；词形变化：s:skeletons','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
