INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c7d1a08c574e2273b2',NULL,'slack','/slæk/','n. 松弛, 松懈, 淡季, 闲散, 家常裤\na. 松弛的, 不流畅的, 疏忽的, 无力的, 呆滞的, 软弱的, 漏水的\nadv. 马虎地, 缓慢地\nvt. 放松, 使缓慢\nvi. 松懈, 减弱, 松弛；英英释义：n. dust consisting of a mixture of small coal fragments and coal dust and dirt that sifts out when coal is passed over a sieve\nn. a stretch of water without current or movement\nn. the quality of being loose (not taut)\nn. a cord or rope or cable that is hanging loosely；词形变化：s:slacks/r:slacker/i:slacking/t:slackest/p:slacked/3:slacks/d:slacked','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_27890da650e544e90e',NULL,'slam','/slæm/','n. 砰然声, 猛然, 猛烈的抨击\nvt. 猛然关上, 砰地关上, 猛烈抨击\nvi. 砰地关上, 猛攻；英英释义：n. winning all or all but one of the tricks in bridge\nn. the noise made by the forceful impact of two objects\nn. a forceful impact that makes a loud noise\nv. close violently；词形变化：p:slammed/i:slamming/d:slammed/3:slams','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_884ca7ec26e3790cb3',NULL,'slap','/slæp/','n. 掴, 掌击, 侮辱, 拍击声\nv. 拍击, 惩罚\nadv. 正面地, 直接地, 突然地；英英释义：n. a blow from a flat object (as an open hand)\nv. hit with something flat, like a paddle or the open hand；词形变化：p:slapped/i:slapping/d:slapped/3:slaps/s:slaps','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b90f576bdfd932b097',NULL,'slaughter','/''slɒ:tә/','n. 残杀, 屠杀, 杀戮\nvt. 残杀, 屠杀, 亏本出售；英英释义：n. the killing of animals (as for food)\nn. the savage and excessive killing of many people；词形变化：d:slaughtered/i:slaughtering/p:slaughtered/3:slaughters/s:slaughters','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
