INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2e545c9bd766cd3a83',NULL,'sleeve','/sli:v/','n. 袖子, 套管\nvt. 缝上袖子；英英释义：n. the part of a garment that is attached at the armhole and that provides a cloth covering for the arm\nn. small case into which an object fits；词形变化：s:sleeves/p:sleeved/i:sleeving/d:sleeved','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_86d7447bfe68828505',NULL,'slender','/''slendә/','a. 苗条的, 纤弱的, 微少的, 微薄的\n[机] 细的, 纤细的；英英释义：s. being of delicate or slender build\ns. very narrow\ns. having little width in proportion to the length or height\ns. small in quantity；词形变化：i:slendering','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fec1d03f529cce42db',NULL,'slice','/slais/','n. 薄的切片, 一部分, 菜刀\nvt. 切成薄片, 切下\nvi. 切\n[计] 片；英英释义：n. a share of something\nn. a golf shot that curves to the right for a right-handed golfer\nn. a thin flat piece cut off of some object\nn. a spatula for spreading paint or ink；词形变化：s:slices/i:slicing/p:sliced/d:sliced/3:slices','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
