INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_478dc60dbc2b7ba662',NULL,'snake','/sneik/','n. 蛇, 阴险的人\nvi. 曲折行进\nvt. 迂回, 拉, 急抽；英英释义：n. limbless scaly elongate reptile; some are venomous\nn. a deceitful or treacherous person\nn. a tributary of the Columbia River that rises in Wyoming and flows westward; discovered in 1805 by the Lewis and Clark Expedition\nn. something long, thin, and flexible that resembles a snake；词形变化：s:snakes/p:snaked/i:snaking/3:snakes/d:snaked','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_734917f18cbd0870c3',NULL,'snap','/snæp/','vt. 使突然中断, 猛咬, 争夺, 拉断, 使有啪啪声, 厉声说, 突然射击, 用快照拍摄\nvi. 咬, 扑, 抓, 折断, 劈啪地响, 厉声说, 砰然关上\nn. 猛咬, 猛扑, 劈啪声, 申斥, 快照, 活力, 一般时期的寒冷天气, 揿钮\na. 突然的, 装搭扣的\nadv. 猛地\n[计] 子网访问协议；英英释义：n. a spell of cold weather\nn. the noise produced by the rapid movement of a finger from the tip to the base of the thumb on the same hand\nn. a sudden breaking\nn. a fastener used on clothing; fastens with a snapping sound；词形变化：p:snapped/d:snapped/i:snapping/3:snaps/s:snaps','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
