INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_924992b5ca43dedacb',NULL,'soluble','/''sɒljubl/','a. 溶解的, 可溶解的, 可以解决的\n[医] 溶解的, 可溶的；英英释义：a. (of a substance) capable of being dissolved in some solvent (usually water)\na. susceptible of solution or of being solved or explained；词形变化：s:solubles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1d856f5395cc7b668c',NULL,'solution','/sә''lu:ʃәn/','n. 解决, 解答, 溶液\n[化] 溶液；英英释义：n. a homogeneous mixture of two or more substances; frequently (but not necessarily) a liquid solution\nn. a statement that solves a problem or explains how to solve the problem\nn. a method for solving a problem\nn. the set of values that give a true statement when substituted into an equation；词形变化：s:solutions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
