INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6482bae747cca6dd97',NULL,'southern','/''sʌðәn/','n. 南方人, 男风\na. 向南方的, 来自南方的；英英释义：a. in or characteristic of a region of the United States south of (approximately) the Mason-Dixon line\na. situated in or coming from regions of the south','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b9ab6feb411db97d5d',NULL,'southwest','/sauθ''west/','n. 西南, 西南方, 西南地区\na. 西南的, 来自西南方的\nadv. 往西南, 来自西南；英英释义：n. the compass point midway between south and west; at 225 degrees\nn. the southwestern region of the United States generally including New Mexico, Arizona, Texas, Nevada, California, and sometimes Utah and Colorado\nn. the direction corresponding to the southwestward compass point','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_613aaaeed44263c7ac',NULL,'sovereign','/''sɒvrin/','n. 元首, 独立国\na. 具有主权的, 至高无上的, 国王的, 完全的；英英释义：n. a nation''s ruler or head of state usually by hereditary right\ns. greatest in status or authority or power；词形变化：s:sovereigns','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8fb4af39e574adf46a',NULL,'sow','/sau. sәu/','n. 母猪, 懒胖女人\nvt. 播种, 散布, 使密布\nvi. 播种；英英释义：n. an adult female hog\nv. place (seeds) in or on the ground for future growth\nv. introduce into an environment；词形变化：d:sown/s:sows/i:sowing/p:sowed/3:sows','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_25d0d5401c16668ef7',NULL,'space','/speis/','n. 位置, 空间, 距离, 太空, 空白, 间隔, (期刊等的)篇幅\nvt. 隔开, 分隔\nvi. 留间隔\n[计] 空白, 空格校验；英英释义：n. the unlimited expanse in which everything is located\nn. an empty area (usually bounded in some way between things)\nn. an area reserved for some particular purpose\nn. a blank character used to separate successive words in writing or printing；词形变化：s:spaces/d:spaced/i:spacing/p:spaced/3:spaces','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dee849ce38402153e3',NULL,'spacecraft','/''speiskræft/','n. 航天飞船；英英释义：n. a craft capable of traveling in outer space; technically, a satellite around the sun；词形变化：s:spacecrafts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
