INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_618068b8ec7fe85056',NULL,'spacious','/''speiʃәs/','a. 广大的, 宽广的；英英释义：s very large in expanse or scope\ns (of buildings and rooms) having ample space','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_326736ea6ee5922c69',NULL,'spade','/speid/','n. 铲子, 锄, 铲刀, 黑桃\nvt. 以锄掘, 把...弄实抹平\nvi. 铲；英英释义：n. a playing card in the major suit that has one or more black figures on it\nn. a sturdy hand shovel that can be pushed into the earth with the foot\nv. dig (up) with a spade；词形变化：s:spades/i:spading/p:spaded/3:spades/d:spaded','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_05e1de828875b89572',NULL,'span','/spæn/','n. 指距, 全长, 跨距, 一段时间, 小范围\nvt. 以手指测量, 跨越, 架设, 持续；英英释义：n. the complete duration of something\nn. the distance or interval between two points\nn. a unit of length based on the width of the expanded human hand (usually taken as 9 inches)；词形变化：i:spanning/p:spanned/3:spans/s:spans/d:spanned/0:span/1:dp','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_31b460993481342b49',NULL,'spark','/spɑ:k/','n. 火花, 火星, 闪光, 无线电报务员, 瞬间放电, 活力, 朝气, 花花公子, 情郎\nvi. 闪光, 发火花, 求婚\nvt. 发动, 鼓舞, 使有朝气, 求婚；英英释义：n. a small but noticeable trace of some quality that might become stronger\nn. Scottish writer of satirical novels (born in 1918)\nn. a small fragment of a burning substance thrown out by burning material or by friction\nv. emit or produce sparks；词形变化：s:sparks/p:sparked/d:sparked/i:sparking/3:sparks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8d7375961f4414a07c',NULL,'sparkle','/''spɑ:kl/','n. 闪耀, 火花, 活力, 发泡\nvi. 闪耀, 冒火花\nvt. 使闪耀；英英释义：n. merriment expressed by a brightness or gleam or animation of countenance\nv. reflect brightly\nv. be lively or brilliant or exhibit virtuosity；词形变化：p:sparkled/i:sparkling/3:sparkles/s:sparkles/d:sparkled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9cdca1e7983ebad34f',NULL,'speaker','/''spi:kә/','n. 说话人, 讲演者, 发言人, 喇叭, 扬声器\n[计] 扬声器；英英释义：n. someone who expresses in language; someone who talks (especially someone who delivers a public speech or someone especially garrulous)\nn. the presiding officer of a deliberative assembly；词形变化：s:speakers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e5dd1e1a7bf085b540',NULL,'spear','/spiә/','n. 矛, 枪, 持矛者, 嫩枝\nvt. 用矛刺\nvi. 刺, 戳\na. 父系的；英英释义：n. a long pointed rod used as a tool or weapon\nn. an implement with a shaft and barbed point used for catching fish\nv. pierce with a spear\nv. thrust up like a spear；词形变化：s:spears/p:speared/d:speared/i:spearing/3:spears','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bd8aa4a8c9dc0f3f63',NULL,'special','/''speʃәl/','n. 专辑, 专车, 号外, 特别的东西, 负有特别任务的人员\na. 特别的, 专门的, 特殊的, 额外的, 附加的, 特别亲密的；英英释义：n. a special offering (usually temporary and at a reduced price) that is featured in advertising\nn. a dish or meal given prominence in e.g. a restaurant\nn. a television production that features a particular person or work or topic\ns. for a special service or occasion；词形变化：s:specials','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c3c92a3324ba43090f',NULL,'specialist','/''speiʃәlist/','n. 专门医师, 专家\na. 专业的, 专家的；英英释义：n. an expert who is devoted to one occupation or branch of learning\nn. practices one branch of medicine；词形变化：s:specialists','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0aec67248f4e2b9d1e',NULL,'speciality','/.speʃi''æliti/','n. 专长, 擅长, 特种技能, 详细说明, 特性, 特产, 专业\n[化] 特制品；英英释义：n an asset of special worth or utility\nn a distinguishing trait\nn the special line of work you have adopted as your career；词形变化：s:specialities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ddca84d53669ae7003',NULL,'specialize','/''speʃәlaiz/','vt. 使特殊化, 列举, 特别指明, 限定...的范围\nvi. 成为专家, 专攻；英英释义：v. become more focus on an area of activity or field of study\nv. suit to a special purpose\nv. devote oneself to a special area of work；词形变化：i:specializing/p:specialized/d:specialized/3:specializes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_eec15c4104d41a7f75',NULL,'species','/''spi:ʃiz/','n. 种, 类, 外形\n[医] 茶剂; 种；英英释义：n. (biology) taxonomic group whose members can interbreed\nn. a specific kind of something','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e94c121dd910e37bfb',NULL,'specific','/spi''sifik/','n. 特效药, 特性\na. 特殊的, 明确的, 具有特效的, 特定地, 具体地；英英释义：n. a medicine that has a mitigating effect on a specific disease\na. (sometimes followed by `to'') applying to or characterized by or distinguishing something particular or special or unique\ns. stated explicitly or in detail\na. relating to or distinguishing or constituting a taxonomic species；词形变化：s:specifics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a36884d4ae39c79779',NULL,'specification','/.spesifi''keiʃәn/','n. 规格, 详述, 详细说明书\n[计] 规范; 形式说明; 说明; 说明书; 规格；英英释义：n. a detailed description of design criteria for a piece of work\nn. naming explicitly\nn. (patent law) a document drawn up by the applicant for a patent of invention that provides an explicit and detailed description of the nature and use of an invention；词形变化：s:specifications','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('babda2d1-7a48-48eb-86a0-66942d82fa1a',NULL,'specify','/''spesifai/','vt. 详列, 指定, 说明\n[计] 指定；英英释义：v. decide upon or fix definitely\nv. determine the essential quality of\nv. be specific about；词形变化：d:specified/i:specifying/p:specified/3:specifies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f2d661dcade48ada79',NULL,'specimen','/''spesimәn/','n. 样品, 标本, 试料\n[化] 试样；英英释义：n. an example regarded as typical of its class\nn. a bit of tissue or blood or urine that is taken for diagnostic purposes；词形变化：s:specimens','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_14116926415b9bd780',NULL,'spectacle','/''spektәkl/','n. 引人羡慕的东西, 景象, 眼镜, 场面, 公开展示；英英释义：n. something or someone seen (especially a notable or unusual sight)\nn. an elaborate and remarkable display on a lavish scale\nn. a blunder that makes you look ridiculous; used in the phrase `make a spectacle of'' yourself；词形变化：s:spectacles/p:spectacled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_07ad02d86fdeeede45',NULL,'spectacular','/spek''tækjulә/','a. 公开展示的, 惊人的, 壮观的\nn. 奇观, 惊人之举, 展览物；英英释义：n. a lavishly produced performance\ns. characteristic of spectacles or drama；词形变化：s:spectaculars','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_87dd9d910d74153751',NULL,'spectator','/spek''teitә/','n. 观众, 目击者, 旁观者；英英释义：n. a close observer; someone who looks at something (such as an exhibition of some kind)；词形变化：s:spectators','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('68a0aaf6-e1f9-4bde-99a7-bef836cdd99b',NULL,'spectrum','/''spektrәm/','n. 光谱, 范围, 系列\n[化] 光谱；英英释义：n. an ordered array of the components of an emission or wave\nn. a broad range of related objects or values or qualities or ideas or activities；词形变化：s:spectra','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('de5366ee-b60d-4219-91c7-0fd697576a35',NULL,'speculate','/''spekjuleit/','vi. 深思, 推测, 投机\n[经] 投机；英英释义：v. to believe especially on uncertain or tentative grounds\nv. talk over conjecturally, or review in an idle or casual way and with an element of doubt or without sufficient reason to reach a conclusion\nv. invest at a risk；词形变化：i:speculating/p:speculated/d:speculated/3:speculates','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_93d2db29400569ad88',NULL,'speech','/spi:tʃ/','n. 演讲, 说话, 谈话, 言语, 引语, 民族语言\n[医] 言语, 语言；英英释义：n. (language) communication by word of mouth\nn. something spoken\nn. the exchange of spoken words；词形变化：s:speeches','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_303de205e3b0308b92',NULL,'speed','/spi:d/','n. 速率, 速度, 迅速\nvi. 加速, 超速, 快进\nvt. 快速传送, 促进, 使加速\n[计] 中央处理机速度设置程序；英英释义：n. distance travelled per unit time\nn. a rate (usually rapid) at which something happens\nn. changing location rapidly\nv. travel at an excessive or illegal velocity；词形变化：s:speeds/i:speeding/p:sped/3:speeds/d:speeded','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8e5721d4bfaa5e02f3',NULL,'spell','/spel/','n. 符咒, 魅力, 轮值, 轮班, 工作时间, 一次发作\nvt. 拼写, 拼成, 琢磨, 理解, 招致, 轮换, 迷住\nvi. 轮换, 拼字；英英释义：n. a verbal formula believed to have magical force\nv. orally recite the letters of or give the spelling of\nv. indicate or signify\nv. write or name the letters that comprise the conventionally accepted form of (a word or part of a word)；词形变化：s:spells/d:spelt/3:spells/i:spelling/p:spelt','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9f504c0c8777914b69',NULL,'spelling','/''speliŋ/','n. 拼, 拼字, 拼法\n[计] 拼写检查；英英释义：n. forming words with letters according to the principles underlying accepted usage；词形变化：0:spell/1:i/i:spelling/s:spellings','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6c6ec945a164cf7eb8',NULL,'sphere','/sfiә/','n. 球, 球面, 球体, 天体, 地球仪, 范围\nvt. 包围, 使成球体, 放入球内；英英释义：n. a particular environment or walk of life\nn. any spherically shaped artifact\nn. the geographical area in which one nation is very influential\nn. a solid figure bounded by a spherical surface (including the space it encloses)；词形变化：s:spheres','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_af6b2d8dff29c02c08',NULL,'spicy','/''spaisi/','a. 香的, 多香料的, 辛辣的, 下流的；英英释义：s having an agreeably pungent taste\ns producing a burning sensation on the taste nerves\ns suggestive of sexual impropriety；词形变化：r:spicier/t:spiciest','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_367e85f96ac916740b',NULL,'spider','/''spaidә/','n. 蜘蛛, 设圈套者\n[化] 星形轮；英英释义：n. predatory arachnid with eight legs, two poison fangs, two feelers, and usually two silk-spinning organs at the back end of the body; they spin silk to make cocoons for eggs or traps for prey\nn. a computer program that prowls the internet looking for publicly accessible resources that can be added to a database; the database can then be searched with a search engine\nn. a skillet made of cast iron；词形变化：s:spiders','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a083edff10bf1fa711',NULL,'spill','/spil/','n. 溢出, 溅出, 摔下, 溢出量, 木片, 小塞子\nvt. 使溢出, 使散落, 洒, 使流出, 倒出, 使摔下\nvi. 溢出, 涌流, 摔下；英英释义：n. liquid that is spilled\nn. the act of allowing a fluid to escape\nn. a sudden drop from an upright position\nv. cause or allow (a liquid substance) to run or flow from a container；词形变化：i:spilling/p:spilled/3:spills/d:spilled/s:spills','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c19b27bccf3c138c53',NULL,'spin','/spin/','n. 旋转, 自旋, 疾驰, 情绪低落\nvt. 纺织, 纺, 使旋转, 编造\nvi. 纺纱, 吐丝, 作茧, 结网, 旋转, 自旋, 疾驰；英英释义：n. a swift whirling motion (usually of a missile)\nn. the act of rotating rapidly\nn. a short drive in a car\nn. a distinctive interpretation (especially as used by politicians to sway public opinion)；词形变化：i:spinning/p:spun/d:spun/3:spins/s:spins','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dbf70ae0e7e8338c93',NULL,'spine','/spain/','n. 背骨, 脊柱, 尖刺\n[医] 脊柱; 棘, 刺; 马蹄嵴；英英释义：n. a small sharp-pointed tip resembling a spike on a stem or leaf\nn. the part of a book''s cover that encloses the inner side of the book''s pages and that faces outward when the book is shelved\nn. a sharp rigid animal process or appendage; as a porcupine quill or a ridge on a bone or a ray of a fish fin；词形变化：s:spines','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c789a827caace712d1',NULL,'spiral','/''spairәl/','n. 螺旋形之物, 螺线\na. 螺旋形的, 盘旋的\nvi. 螺旋形下降, 螺旋形上升, 螺旋形行进\nvt. 使螺旋形行进；英英释义：n. a plane curve traced by a point circling about the center but at increasing distances from the center\nn. a continuously accelerating change in the economy\nn. ornament consisting of a curve on a plane that winds around a center with an increasing distance from the center\nn. flying downward in a helical path with a large radius；词形变化：s:spirals/i:spiralling/p:spiralled/3:spirals/d:spiralled','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5be76c04becb112598',NULL,'spirit','/''spirit/','n. 精神, 心灵, 灵魂, 态度, 志气, 人格, 情绪, 心情, 烈酒\nvt. 诱拐, 鼓励, 鼓舞；英英释义：n. the vital principle or animating force within living things\nn. the general atmosphere of a place or situation and the effect that it has on people\nn. a fundamental emotional and activating principle determining one''s character\nn. any incorporeal supernatural being that can become visible (or audible) to human beings；词形变化：s:spirits/d:spirited/p:spirited/i:spiriting/3:spirits','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1ec86d33fc1fb9e46c',NULL,'spiritual','/''spiritʃuәl/','a. 精神上的, 神圣的, 崇高的, 高尚的, 鬼的, 招魂术的\nn. 有关教会的事；英英释义：n. a kind of religious song originated by Blacks in the southern United States\ns. concerned with or affecting the spirit or soul\ns. lacking material body or form or substance；词形变化：s:spirituals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bc9da3ae56138f85ac',NULL,'spit','/spit/','n. 唾液, 唾吐, 小雨, 炙叉, 一铲的深度\nvt. 唾吐, 吐出, 降小雨, 用炙叉穿过\nvi. 吐唾沫, 吐痰, 唾弃, 飘霏霏细雨；英英释义：n. a narrow strip of land that juts out into the sea\nn. a skewer for holding meat over a fire\nn. the act of spitting (forcefully expelling saliva)\nv. expel or eject (saliva or phlegm or sputum) from the mouth；词形变化：d:spat/p:spat/i:spitting/3:spits/1:pd/0:spit/s:spits','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
