INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ec25f538a32bad567e',NULL,'stage','/steidʒ/','n. 阶段, 舞台, 场所, 戏剧, 站, 驿站, 级, 层, 脚手架\nvt. 上演, 表演, 筹划\nvi. 适于上演, 乘驿车旅行；英英释义：n. a large platform on which people can stand and can be seen by an audience\nn. the theater as a profession (usually `the stage'')\nn. a section or portion of a journey or course\nn. any scene regarded as a setting for exhibiting or doing something；词形变化：s:stages/d:staged/p:staged/i:staging/3:stages','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_97f55a27ac42a395d8',NULL,'stagger','/''stægә/','n. 蹒跚, 踌躇\nvi. 蹒跚, 犹豫\nvt. 使摇摆, 使踌躇, 交错, 错开\na. 交错的, 错开的；英英释义：v. walk as if unable to control one''s movements\nv. walk with great difficulty\nv. to arrange in a systematic order\nv. astound or overwhelm, as with shock；词形变化：p:staggered/i:staggering/d:staggered/s:staggers/3:staggers','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2dc3541399e7a5fce2',NULL,'staggering','/''stægәriŋ/','a. 蹒跚的, 巨大的, 惊人的\n[电] 参差；英英释义：v walk as if unable to control one''s movements\nv walk with great difficulty\nv to arrange in a systematic order\nv astound or overwhelm, as with shock\ns so surprisingly impressive as to stun or overwhelm；词形变化：0:stagger/1:i/i:staggering','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
