INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_af531085f3d2057512',NULL,'stale','/steil/','n. 尿\na. 不新鲜的, 陈腐的, 疲惫的, 陈旧的\nvt. 使变旧, 走味\nvi. 变陈旧, 走味, 失时效, 撒尿；英英释义：v. urinate, of cattle and horses\na. lacking freshness, palatability, or showing deterioration from age；词形变化：r:staler/p:staled/s:stales/i:staling/t:stalest/3:stales/d:staled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
