INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_40590da109f3435ee1',NULL,'steward','/''stju:wәd/','n. 管理人, 招待员, 管家, 乘务员\n[经] 轮船, 飞机的服务员, (财务)管理员；英英释义：n. someone who manages property or other affairs for someone else\nn. the ship''s officer who is in charge of provisions and dining arrangements\nn. an attendant on an airplane；词形变化：s:stewards/i:stewarding/p:stewarded','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
