INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2905cac831fb579316',NULL,'stiff','/stif/','a. 坚硬的, 严厉的, 呆板的, 生硬的, 刚强的, 强烈的, 粘的, 稠的, 艰难的\nn. 死尸, 醉鬼, 钞票\nvt. 不肯付...小费；英英释义：n. an ordinary man\ns. not moving or operating freely\ns. powerful\nr. extremely；词形变化：r:stiffer/s:stiffs/t:stiffest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6391908c42a241067a',NULL,'stimulate','/''stimjuleit/','vt. 刺激, 激励, 鼓舞\nvi. 起刺激作用；英英释义：v. act as a stimulant\nv. stir the feelings, emotions, or peace of\nv. cause to be alert and energetic\nv. stir feelings in；词形变化：d:stimulated/3:stimulates/p:stimulated/i:stimulating','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_04ea764083043230e1',NULL,'sting','/stiŋ/','n. 叮, 刺痛, 刺激, 讽刺\nvt. 叮, 刺痛, 刺激, 使苦恼\nvi. 叮, 刺痛；英英释义：n. a kind of pain; something as sudden and painful as being stung\nn. a painful wound caused by the thrust of an insect''s stinger into skin\nv. deliver a sting to\nv. cause an emotional pain, as if by stinging；词形变化：d:stung/p:stung/s:stings/3:stings/i:stinging','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('dc6f8928-f753-4e44-9d7b-fbe345107e55',NULL,'stipulate','/''stipjuleit/','v. 规定, 保证；英英释义：v. specify as a condition or requirement in a contract or agreement; make an express demand or provision in an agreement\nv. give a guarantee or promise of\nv. make an oral contract or agreement in the verbal form of question and answer that is necessary to give it legal force；词形变化：p:stipulated/d:stipulated/3:stipulates/i:stipulating','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ac7af121c9a225742b',NULL,'stir','/stә:/','n. 骚动, 轰动, 搅动, 监狱\nvt. 移动, 摇动, 激起, 惹起, 搅拌\nvi. 走动, 传播, 搅拌；英英释义：n. a prominent or sensational but short-lived news event\nn. emotional agitation and excitement\nv. move an implement through\nv. move very slightly；词形变化：p:stirred/i:stirring/d:stirred/3:stirs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
