INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_632e1cd4027de03717',NULL,'strap','/stræp/','n. 带, 皮带\nvt. (用皮带)捆扎；英英释义：n. an elongated leather strip (or a strip of similar material) for binding things together or holding something in position\nn. hanger consisting of a loop of leather suspended from the ceiling of a bus or train; passengers hold onto it\nn. a band that goes over the shoulder and supports a garment or bag\nn. whip consisting of a strip of leather used in flogging；词形变化：s:straps/d:strapped/p:strapped/i:strapping/3:straps','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
