INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b38b03f372bcfe4361',NULL,'strengthen','/''streŋθәn/','vt. 加强, 变坚固\nvi. 变强, 股票上涨；英英释义：v. make strong or stronger\nv. gain strength；词形变化：d:strengthened/i:strengthening/p:strengthened/3:strengthens','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
