INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_971312edc887ec2b6e',NULL,'strike','/straik/','n. 罢工, 打击, 殴打\nvt. 打, 撞击, 冲击, 侵袭, 取消, 结算, 打掉, 罢工, 刺透, 使生根, 遇见\nvi. 打, 打击, 抓, 罢工, 搏动, 触礁, 敲, 响, 穿透, 打动；英英释义：n. a group''s refusal to work in protest against low pay or bad work conditions\nn. an attack that is intended to seize or inflict damage on or destroy an objective\nn. a score in tenpins: knocking down all ten with the first ball\nn. (baseball) a pitch that the batter swings at and misses, or that the batter hits into foul territory, or that the batter does not swing at but the umpire judges to be in the area over home plate and between the batter''s knees and shoulders；词形变化：p:struck/d:struck/s:strikes/3:strikes/i:striking','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_49b89bba288568bc1e',NULL,'striking','/''straikiŋ/','a. 醒目的, 惊人的, 打击的, 罢工的\n[法] 罢工的, 罢市的, 罢课的；英英释义：n the physical coming together of two or more things\nn the act of contacting one thing with another\nv deliver a sharp blow, as with the hand, fist, or weapon\nv have an emotional or cognitive impact upon\nv hit against; come into sudden contact with\nv make a strategic, offensive, assault against an enemy, opponent, or a target\nv indicate (a certain time) by striking\nv affect or afflict suddenly, usually adversely\nv stop work in order to press demands\nv touch or seem as if touching visually or audibly\nv attain\nv produce by manipulating keys or strings of musical instruments, also metaphorically\nv cause to form (an electric arc) between electrodes of an arc lamp\nv find unexpectedly\nv produce by ignition or a blow\nv remove by erasing or crossing out or as if by drawing a line\nv cause to experience suddenly\nv drive something violently into a location\nv occupy or take on\nv form by stamping, punching, or printing\nv smooth with a strickle\nv pierce with force\nv arrive at after reckoning, deliberating, and weighing\ns sensational in appearance or thrilling in effect\ns having a quality that thrusts itself into attention；词形变化：0:strike/1:i/i:striking','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_25be98ef54ee7c14b4',NULL,'string','/striŋ/','n. 线, 细绳, 一串, 字符串\nvt. 串起, 成串, 收紧, 缚, 扎\nvi. 成一串\n[计] 字符串, 串；英英释义：n. a lightweight cord\nn. a tightly stretched cord of wire or gut, which makes sound when plucked, struck, or bowed\nn. a sequentially ordered set of things or events or ideas in which each successive member is related to the preceding\nn. a linear sequence of symbols (characters or words or phrases)；词形变化：s:strings/d:strung/i:stringing/3:strings/p:strung','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
