INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7cea549327b187a5cf',NULL,'stun','/stʌn/','vt. 使昏迷, 使震惊, 打昏\nn. 昏迷, 猛击；英英释义：v. make senseless or dizzy by or as if by a blow\nv. overcome as with astonishment or disbelief；词形变化：d:stunned/p:stunned/3:stuns/i:stunning/s:stuns','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
