INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c01cbeb0dc6296616b',NULL,'sturdy','/''stә:di/','a. 强健的, 健全的\n[医] 羊晕倒病, 羊蹒跚病；英英释义：s. substantially made or constructed；词形变化：r:sturdier/t:sturdiest','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8569eba2726ec7c378',NULL,'style','/stail/','n. 风格, 时尚, 文体, 风度, 字体, 类型\nvt. 称呼, (根据新款式)设计, 使合潮流\nn. 风格, 样式\n[计] 风格, 样式；英英释义：n. a particular kind (as to appearance)\nn. (botany) the narrow elongated part of the pistil between the ovary and the stigma\nn. editorial directions to be followed in spelling and punctuation and capitalization and typographical display\nn. a slender bristlelike or tubular process；词形变化：s:styles/d:styled/p:styled/i:styling/3:styles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_051de41d7eb7679325',NULL,'subjective','/sәb''dʒektiv/','a. 主观的, 个人的\n[医] 主观的, 自觉的；英英释义：a. taking place within the mind and modified by individual bias','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_da774c48d064a36581',NULL,'submarine','/''sʌbmәri:n/','n. 潜水艇, 海底生物\na. 海中的, 生长在海中的\nvt. 用潜水艇攻击\nvi. 在下疾行, 在下滑动；英英释义：n. a submersible warship usually armed with torpedoes\nv. move forward or under in a sliding motion\nv. throw with an underhand motion\nv. bring down with a blow to the legs；词形变化：s:submarines/i:submarining/p:submarined/3:submarines/d:submarined','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_861967753c0895e537',NULL,'submerge','/sәb''mә:dʒ/','vt. 使浸水, 使陷入, 淹没\nvi. 潜入水中；英英释义：v. sink below the surface; go under or as if under water\nv. cover completely or make imperceptible\nv. put under water；词形变化：d:submerged/i:submerging/p:submerged/3:submerges/s:submerges','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c12761dd397af2e860',NULL,'submit','/sәb''mit/','vt. 使服从, 使受到, 委托, 提交, 认为\nvi. 屈服, 服从；英英释义：v. refer for judgment or consideration\nv. put before\nv. yield to the control of another\nv. yield to another''s wish or opinion；词形变化：d:submitted/p:submitted/i:submitting/3:submits','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('94e8d7cf-9ea8-44c5-98c4-38bbed711cc2',NULL,'subordinate','/sә''bɒ:dnit/','n. 属下, 附属物\na. 下级的, 次要的, 附属的\nvt. 使居下位, 使服从；英英释义：n. an assistant subject to the authority or control of another\nv. rank or order as less important or consider of less value\nv. make subordinate, dependent, or subservient\na. lower in rank or importance；词形变化：s:subordinates/d:subordinated/p:subordinated/i:subordinating/3:subordinates','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_995f96fef3361610b5',NULL,'subscribe','/sәb''skraib/','vt. 捐献, 签署\nvi. 赞成, 同意, 捐款, 预订, 认购\n[计] 订阅；英英释义：v. offer to buy, as of stocks and shares\nv. adopt as a belief\nv. receive or obtain regularly；词形变化：d:subscribed/i:subscribing/p:subscribed/3:subscribes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('27760454-db8f-451f-a9ca-6920a3ed40b9',NULL,'subsequent','/''sʌbsikwәnt/','a. 后来的, 接下去的\n[经] 后来的；英英释义：a. following in time or order','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e59468ecac845550b5',NULL,'subsidiary','/sәb''sidiәri/','n. 子公司, 附件, 辅助者\na. 辅助的, 次要的, 津贴的；英英释义：n an assistant subject to the authority or control of another\nn a company that is completely controlled by another company\ns functioning in a supporting capacity；词形变化：s:subsidiaries','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_970849859748be0110',NULL,'subsidize','/''sʌbsidaiz/','vt. 补助, 资助, 贿赂\n[经] 资助, 津贴, 给...补助金；英英释义：v. support through subsidies\nv. secure the assistance of by granting a subsidy, as of nations or military forces；词形变化：d:subsidized/p:subsidized/i:subsidizing/3:subsidizes','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
